INSERT INTO `cars` (`id`, `brand`, `model`, `variant`, `year`, `fuel`, `power_kw`, `body`, `price`, `mileage`, `created_at`, `description`, `model_3d`) VALUES
(1, 'Ferrari', '488 GTB', '3.9 V8 Biturbo', 2017, 'Benzín', 492, 'Coupé', 4500000, 10000, '2025-10-22 07:48:37', 'Ferrari 488 GTB je moderní supersport, který představuje důležitý milník ve vývoji značky Ferrari. Jako nástupce modelu 458 Italia přinesl zásadní změnu v podobě přeplňovaného osmiválcového motoru, který kombinuje extrémní výkon s vysokou efektivitou. Motor je uložen uprostřed vozidla a spolu se zadním pohonem a dvouspojkovou převodovkou poskytuje velmi přesnou odezvu a výjimečné jízdní vlastnosti.\n\nZ pohledu automechanika jde o technicky vysoce náročný vůz, který vyžaduje důsledné dodržování servisních intervalů a správné zacházení. Studený motor nesmí být vytáčen, kvalita oleje a paliva hraje zásadní roli a běžné provozní díly, jako jsou pneumatiky a brzdy, mají kratší životnost než u standardních automobilů. Při dodržení těchto pravidel však dokáže Ferrari 488 GTB nabídnout překvapivě spolehlivý provoz v rámci kategorie supersportů.\n\nMezi hlavní přednosti patří špičkový výkon, precizní ovladatelnost, propracovaná aerodynamika a vysoká technická úroveň celého vozu. Naopak nevýhodou je vysoká pořizovací cena, velmi nákladný servis a omezená praktičnost pro každodenní používání. Ferrari 488 GTB je tak automobil určený především pro nadšence, kteří chápou pravidla provozu supersportovních vozů a jsou ochotni jim přizpůsobit způsob používání i údržby.', NULL),
(2, 'Ferrari', '812 Superfast', '6.5 V12', 2020, 'Benzín', 588, 'Coupé', 9400000, 25000, '2025-10-22 07:48:37', 'Ferrari 812 Superfast je vrcholný supersport s klasickou koncepcí motoru vpředu, který navazuje na dlouhou tradici dvanáctiválcových modelů značky Ferrari. Oproti moderním trendům přeplňování zůstává u atmosférického motoru V12, který nabízí okamžitou odezvu na plyn, vysoké otáčky a charakteristický zvuk, jenž je pro tuto kategorii vozů typický. Model 812 Superfast je zároveň mostem mezi světem čistokrevných supersportů a luxusních grand tourerů.\n\nZ pohledu automechanika se jedná o technicky velmi precizní, ale extrémně náročný automobil. Atmosférický dvanáctiválec pracuje s vysokými otáčkami a teplotami, což klade velké nároky na mazání, chlazení i celkový servis. Vůz vyžaduje striktní dodržování servisních intervalů, kvalitní provozní kapaliny a citlivé zacházení, zejména při studeném motoru. Přesto je konstrukčně považován za spolehlivější než složité přeplňované jednotky, pokud je správně udržován.\n\nMezi hlavní přednosti Ferrari 812 Superfast patří extrémní výkon, lineární nástup síly, vynikající stabilita ve vysokých rychlostech a výjimečný jízdní projev, který je dnes u atmosférických motorů vzácný. Naopak nevýhodou je velmi vysoká pořizovací cena, nákladná údržba, vysoká spotřeba paliva a omezená využitelnost v běžném provozu. Ferrari 812 Superfast je tak určen především pro zkušené řidiče a sběratele, kteří chtějí zažít jednu z posledních čistých podob dvanáctiválcového supersportu.', NULL),
(3, 'Ferrari', 'F8 Tributo', '3.9 V8', 2021, 'Benzín', 530, 'Coupé', 7600000, 20000, '2025-10-22 07:48:37', 'Ferrari F8 Tributo je moderní supersport s motorem uloženým uprostřed, který navazuje na model 488 GTB a zároveň vzdává hold osmiválcovým motorům Ferrari. Pod kapotou se nachází přeplňovaný V8 o objemu 3,9 litru, který nabízí extrémní výkon, rychlou odezvu a vysokou efektivitu. F8 Tributo patří mezi nejvyspělejší supersporty značky, a to jak po stránce techniky, tak aerodynamiky.\n\nZ pohledu automechanika jde o velmi sofistikovaný vůz, u kterého je klíčová přesná a pravidelná údržba. Přeplňovaný motor pracuje s vysokými teplotami a tlakem, což klade nároky na chlazení, mazání a kvalitu provozních kapalin. Vůz vyžaduje šetrné zacházení při studeném startu, dodržování servisních intervalů a kvalitní palivo. Při správné údržbě však dokáže nabídnout vysokou spolehlivost v rámci kategorie supersportů.\n\nMezi hlavní přednosti Ferrari F8 Tributo patří špičkový výkon, velmi rychlá akcelerace, precizní ovladatelnost a výrazně vylepšená aerodynamika oproti předchozí generaci. Nevýhodou je vysoká pořizovací cena, nákladný servis, omezená praktičnost a citlivost na styl jízdy. Ferrari F8 Tributo je tak určen především pro zkušené řidiče, kteří hledají moderní, technicky vyspělý supersport a jsou připraveni respektovat pravidla jeho provozu.', NULL),
(4, 'Ferrari', 'Roma', '3.9 V8', 2022, 'Benzín', 456, 'Coupé', 6800000, 15000, '2025-10-22 07:48:37', 'Ferrari Roma je elegantní sportovní vůz typu grand tourer, který představuje moderní pojetí klasického Ferrari s motorem vpředu. Designem i charakterem se odklání od čistokrevných okruhových supersportů a zaměřuje se na kombinaci výkonu, komfortu a každodenní použitelnosti. Pod kapotou se nachází přeplňovaný osmiválcový motor, který nabízí dostatek výkonu pro dynamickou jízdu, ale zároveň kultivovaný projev při běžném provozu.\n\nZ pohledu automechanika je Ferrari Roma technicky velmi vyspělý vůz, který klade důraz na moderní elektroniku, asistenty a komfortní systémy. Přeplňovaný V8 pracuje s vysokou účinností, ale vyžaduje kvalitní palivo, olej a důsledné dodržování servisních intervalů. Oproti čistokrevným supersportům je Roma méně extrémní na provoz, přesto však platí, že nesprávné zacházení nebo zanedbaná údržba mohou vést k nákladným opravám.\n\nMezi hlavní přednosti Ferrari Roma patří elegantní design, vyvážený poměr mezi sportovním výkonem a komfortem, kvalitní interiér a vyšší použitelnost pro každodenní jízdu. Nevýhodou je vysoká pořizovací cena, nákladný servis a menší praktičnost oproti běžným vozům. Ferrari Roma je ideální volbou pro řidiče, kteří chtějí sportovní charakter Ferrari v civilnějším a kultivovanějším provedení.', NULL),
(5, 'Ferrari', 'Portofino', '3.9 V8', 2021, 'Benzín', 441, 'Kabriolet', 5400000, 40000, '2025-10-22 07:48:37', 'Ferrari Portofino je sportovní vůz kategorie grand tourer s motorem vpředu a skládací pevnou střechou, který kombinuje dynamiku značky Ferrari s komfortem a každodenní použitelností. Jde o nástupce modelu California a je navržen tak, aby oslovil řidiče hledající sportovní charakter Ferrari bez extrémních nároků typických pro supersporty. Pod kapotou se nachází přeplňovaný osmiválcový motor, který nabízí vysoký výkon, plynulý zátah a kultivovaný projev.\n\nZ pohledu automechanika je Ferrari Portofino technicky složitější vůz především kvůli kombinaci výkonného motoru, pokročilé elektroniky a mechanismu skládací střechy. Přeplňovaný V8 klade nároky na chlazení, mazání a kvalitu paliva, zatímco střešní mechanismus vyžaduje pravidelnou kontrolu a údržbu. Při dodržování servisních intervalů a správném zacházení je však Portofino spolehlivým sportovním GT vhodným i pro delší cesty.\n\nMezi hlavní přednosti Ferrari Portofino patří atraktivní design, silný motor, komfortní podvozek a možnost otevřené jízdy. Nevýhodou je vyšší hmotnost oproti kupé, nákladný servis a omezená praktičnost v běžném provozu. Ferrari Portofino je ideální volbou pro řidiče, kteří chtějí sportovní Ferrari s otevřenou střechou, ale zároveň očekávají určitý komfort a univerzálnost.', NULL),
(6, 'Lamborghini', 'Huracán EVO', '5.2 V10', 2020, 'Benzín', 470, 'Coupé', 5800000, 10000, '2025-10-22 07:48:37', 'Lamborghini Huracán EVO je moderní supersport, který reprezentuje typický charakter značky Lamborghini – extrémní design, vysoký výkon a emotivní jízdní projev. Vůz je poháněn atmosférickým desetiválcovým motorem uloženým uprostřed, který nabízí okamžitou odezvu na plyn, vysoké otáčky a výrazný zvukový projev. Huracán EVO je evolucí původního modelu Huracán a přináší výrazná vylepšení v oblasti elektroniky, aerodynamiky a ovladatelnosti.\n\nZ pohledu automechanika se jedná o technicky velmi vyspělý automobil, u kterého hraje klíčovou roli správná údržba a zacházení. Atmosférický V10 je mechanicky odolný, ale pracuje s vysokými otáčkami a teplotami, což klade nároky na kvalitní olej, chlazení a dodržování servisních intervalů. Velký důraz je kladen také na elektronické systémy řízení jízdní dynamiky, které zásadně ovlivňují chování vozu a vyžadují bezchybný technický stav.\n\nMezi hlavní přednosti Lamborghini Huracán EVO patří výjimečný zvuk motoru, ostrá odezva, agresivní design a velmi přesné řízení podporované moderní elektronikou. Nevýhodou je vysoká pořizovací cena, nákladný servis, omezená praktičnost a citlivost na styl jízdy. Huracán EVO je tak určen především pro nadšence, kteří chtějí zažít čistý atmosférický supersport s výrazným charakterem a jsou připraveni respektovat jeho provozní nároky.', NULL),
(7, 'Lamborghini', 'Aventador S', '6.5 V12', 2019, 'Benzín', 544, 'Coupé', 10500000, 10000, '2025-10-22 07:48:37', 'Lamborghini Aventador S je vlajkový supersport značky Lamborghini, který představuje vrchol techniky a designu této automobilky. Vůz je poháněn atmosférickým dvanáctiválcem uloženým uprostřed, jenž nabízí extrémní výkon, vysoké otáčky a charakteristický agresivní zvuk. Verze „S“ přinesla oproti původnímu Aventadoru výrazná vylepšení v oblasti podvozku, řízení a aerodynamiky, díky čemuž je vůz lépe ovladatelný a stabilnější i při velmi vysokých rychlostech.\n\nZ pohledu automechanika jde o technicky mimořádně náročný automobil, který vyžaduje maximální péči a respekt. Atmosférický V12 pracuje s vysokými teplotami a otáčkami, což klade extrémní nároky na mazání, chlazení a celkový technický stav. Automatizovaná převodovka a aktivní systémy podvozku vyžadují pravidelný odborný servis a bezchybné nastavení. Jakékoli zanedbání údržby se u tohoto typu supersportu velmi rychle projeví.\n\nMezi hlavní přednosti Lamborghini Aventador S patří brutální výkon, jedinečný zvuk dvanáctiválce, ikonický design a výjimečný jízdní projev. Nevýhodou je extrémně vysoká pořizovací cena, velmi nákladný servis, nízká praktičnost a náročnost na každodenní provoz. Aventador S je automobil určený především pro zkušené řidiče a sběratele, kteří chtějí vlastnit jeden z posledních čistokrevných atmosférických supersportů s motorem V12.', NULL),
(8, 'Lamborghini', 'Urus', '4.0 V8 Biturbo', 2021, 'Benzín', 478, 'SUV', 5800000, 60000, '2025-10-22 07:48:37', 'Lamborghini Urus je vysoce výkonné SUV, které spojuje sportovní DNA značky Lamborghini s praktičností a komfortem vozu pro každodenní používání. Na rozdíl od klasických supersportů má motor uložený vpředu a pohon všech kol, což z něj dělá univerzální automobil schopný rychlé jízdy na silnici i jistého chování v horších podmínkách. Přeplňovaný osmiválcový motor poskytuje vysoký výkon a dynamiku, která je v segmentu SUV výjimečná.\n\nZ pohledu automechanika je Lamborghini Urus technicky velmi složitý vůz, který kombinuje výkonný motor, sofistikovaný podvozek a rozsáhlou elektroniku. Turbo V8 pracuje s vysokými tlaky a teplotami, což klade velké nároky na chlazení, mazání a kvalitu paliva. Vůz je vybaven adaptivním podvozkem, aktivními stabilizátory a několika jízdními režimy, jejichž správná funkce je závislá na pravidelném a odborném servisu. Při dodržení servisních intervalů je však Urus schopen nabídnout solidní spolehlivost i při sportovním stylu jízdy.\n\nMezi hlavní přednosti Lamborghini Urus patří kombinace extrémního výkonu, praktičnosti, luxusního interiéru a každodenní použitelnosti. Nevýhodou je vysoká pořizovací cena, velmi nákladná údržba, vyšší hmotnost a spotřeba paliva. Lamborghini Urus je ideální volbou pro řidiče, kteří chtějí sportovní charakter Lamborghini, ale zároveň potřebují prostor, komfort a univerzálnost SUV.', NULL),
(9, 'Lamborghini', 'Gallardo LP560-4', '5.2 V10', 2012, 'Benzín', 412, 'Coupé', 2900000, 45000, '2025-10-22 07:48:37', 'Lamborghini Gallardo LP je jeden z nejdůležitějších modelů v historii značky Lamborghini, který výrazně přispěl k jejímu komerčnímu úspěchu. Jedná se o klasický supersport s motorem uloženým uprostřed, poháněný atmosférickým desetiválcem, který nabízí typický ostrý zvuk, vysoké otáčky a syrový jízdní projev. Označení „LP“ (Longitudinale Posteriore) odkazuje na podélné uložení motoru a zadní orientaci pohonu.\n\nZ pohledu automechanika je Gallardo LP mechanicky poctivý, ale náročný vůz, který vyžaduje pečlivou údržbu. Atmosférický V10 je konstrukčně robustní, avšak citlivý na kvalitu oleje, pravidelné servisní intervaly a správné zahřívání. Starší ročníky s robotizovanou převodovkou E-Gear mohou vyžadovat zvýšenou pozornost kvůli opotřebení spojky, zatímco manuální verze jsou z hlediska spolehlivosti často považovány za odolnější.\n\nMezi hlavní přednosti Lamborghini Gallardo LP patří ikonický design, silný atmosférický motor, autentický supersportovní charakter a relativně „jednodušší“ technika ve srovnání s moderními modely. Nevýhodou je vyšší stáří vozů, nákladný servis, omezená praktičnost a citlivost na styl jízdy. Gallardo LP je ideální volbou pro nadšence, kteří chtějí klasický supersport s výrazným charakterem a jsou připraveni akceptovat jeho provozní nároky.', NULL),
(10, 'Lamborghini', 'Murciélago LP640', '6.5 V12', 2008, 'Benzín', 471, 'Coupé', 8000000, 36000, '2025-10-22 07:48:37', 'Lamborghini Murciélago LP640 je ikonický supersport s atmosférickým dvanáctiválcem, který patří mezi nejvýraznější modely moderní historie značky Lamborghini. Verze LP640 představuje modernizovanou a výkonnější variantu původního Murciélaga, přičemž označení „LP“ (Longitudinale Posteriore) odkazuje na podélné uložení motoru uprostřed vozu. Díky pohonu všech kol a brutálnímu výkonu nabízí LP640 extrémní akceleraci a charakteristický surový jízdní projev.\n\nZ pohledu automechanika se jedná o mechanicky velmi poctivý, ale náročný automobil. Atmosférický V12 pracuje s vysokými teplotami a otáčkami, což klade velké nároky na mazání, chlazení a celkový technický stav. Starší technika v kombinaci s vysokým výkonem znamená, že vůz vyžaduje pravidelný odborný servis a důsledné zahřívání motoru. Robotizovaná převodovka E-Gear může být citlivá na styl jízdy a vyžaduje zvýšenou pozornost při údržbě.\n\nMezi hlavní přednosti Lamborghini Murciélago LP640 patří ikonický design, výjimečný zvuk dvanáctiválce, autentický supersportovní charakter a vysoká sběratelská hodnota. Nevýhodou je velmi nákladný servis, vyšší hmotnost, horší každodenní použitelnost a stáří některých technických komponent. Murciélago LP640 je tak ideální volbou pro nadšence a sběratele, kteří chtějí vlastnit jeden z posledních „analogových“ supersportů Lamborghini s atmosférickým V12.', NULL),
(11, 'Porsche', '911 Carrera S', '3.0 Turbo', 2019, 'Benzín', 331, 'Coupé', 2900000, 45000, '2025-10-22 07:48:37', 'Porsche 911 Carrera S je ikonický sportovní vůz, který dlouhodobě představuje rovnováhu mezi vysokým výkonem, každodenní použitelností a technickou precizností. Na rozdíl od většiny supersportů má motor uložený vzadu, což je pro modelovou řadu 911 typické a výrazně ovlivňuje jízdní projev. Přeplňovaný šestiválcový boxer nabízí rychlou odezvu, plynulý zátah a velmi efektivní přenos výkonu na silnici.\n\nZ pohledu automechanika je Porsche 911 Carrera S technicky propracovaný, ale zároveň relativně spolehlivý sportovní vůz, pokud je správně udržován. Boxerový motor má specifické nároky na mazání a chlazení, avšak při dodržování servisních intervalů a kvalitních provozních kapalin je známý svou dlouhou životností. Podvozek a brzdy jsou konstruovány tak, aby zvládaly jak sportovní jízdu, tak běžný každodenní provoz, což odlišuje 911 od mnoha extrémnějších supersportů.\n\nMezi hlavní přednosti Porsche 911 Carrera S patří přesné řízení, výborná trakce, kvalitní zpracování a vysoká univerzálnost. Nevýhodou je vyšší pořizovací cena, dražší servisní úkony a menší praktičnost oproti běžným vozům. Porsche 911 Carrera S je ideální volbou pro řidiče, kteří chtějí čistý sportovní zážitek, ale zároveň automobil, který lze bez větších kompromisů používat každý den.', NULL),
(12, 'Porsche', '911 GT3', '4.0', 2022, 'Benzín', 375, 'Coupé', 7100000, 15000, '2025-10-22 07:48:37', 'Porsche 911 GT3 je ryze sportovní automobil zaměřený především na jízdní zážitek a okruhové využití. Oproti verzím Carrera se výrazně odlišuje svou filozofií – klade důraz na nízkou hmotnost, precizní ovladatelnost a maximální propojení řidiče s vozem. Motor je atmosférický plochý šestiválec uložený vzadu, který se vyznačuje vysokými otáčkami, okamžitou reakcí na plyn a charakteristickým zvukem typickým pro řadu GT.\n\nZ pohledu automechanika je Porsche 911 GT3 technicky velmi precizní, ale zároveň náročný vůz. Atmosférický motor pracuje ve vysokých otáčkách a vyžaduje důsledné zahřívání, kvalitní olej a přísné dodržování servisních intervalů. Podvozek, brzdy a aerodynamické prvky jsou konstruovány pro vysoké zatížení na okruhu, což znamená rychlejší opotřebení při sportovní jízdě. Při správné údržbě je však GT3 považována za mechanicky velmi spolehlivý sportovní vůz.\n\nMezi hlavní přednosti Porsche 911 GT3 patří extrémně přesné řízení, výjimečná odezva motoru, špičkové jízdní vlastnosti a autentický řidičský zážitek. Nevýhodou je omezený komfort, vyšší hlučnost, tvrdší podvozek a menší vhodnost pro každodenní provoz. Porsche 911 GT3 je ideální volbou pro nadšence, kteří hledají jeden z nejčistších sportovních vozů současnosti a jsou ochotni obětovat komfort ve prospěch maximálního zážitku z jízdy.', NULL),
(13, 'Porsche', '911 Turbo S', '3.8 Turbo', 2021, 'Benzín', 478, 'Coupé', 5300000, 30000, '2025-10-22 07:48:37', 'Porsche 911 Turbo S je vrcholná silniční varianta modelové řady 911, která kombinuje extrémní výkon s vysokou mírou komfortu a každodenní použitelnosti. Na rozdíl od okruhově orientované verze GT3 staví Turbo S na přeplňovaném plochém šestiválci a pohonu všech kol, díky čemuž nabízí mimořádnou akceleraci, stabilitu a jistotu v jakýchkoli podmínkách. Jedná se o jeden z nejrychlejších sériově vyráběných sportovních vozů určených pro běžné silnice.\n\nZ pohledu automechanika je Porsche 911 Turbo S technicky velmi komplexní automobil. Přeplňovaný motor pracuje s vysokým plnicím tlakem a teplotami, což klade nároky na chlazení, mazání a přesné dodržování servisních intervalů. Pohon všech kol, aktivní podvozek a množství elektronických systémů zvyšují jízdní jistotu, ale zároveň znamenají složitější servisní zásahy. Při správné údržbě je však Turbo S považováno za velmi spolehlivý a dlouhodobě odolný sportovní vůz.\n\nMezi hlavní přednosti Porsche 911 Turbo S patří extrémní zrychlení, vysoká stabilita, komfortní podvozek a schopnost zvládat každodenní provoz bez větších kompromisů. Nevýhodou je vysoká pořizovací cena, nákladný servis a menší „syrovost“ oproti čistě sportovní GT3. Porsche 911 Turbo S je ideální volbou pro řidiče, kteří chtějí absolutní výkon a rychlost, ale zároveň očekávají komfort, bezpečnost a univerzálnost.', NULL),
(14, 'Porsche', 'Cayman GTS', '4.0', 2020, 'Benzín', 294, 'Coupé', 2700000, 35000, '2025-10-22 07:48:37', 'Porsche Cayman GTS je sportovní vůz s motorem uloženým uprostřed, který je mezi nadšenci považován za jeden z nejlépe vyvážených modelů značky Porsche. Díky této koncepci nabízí výjimečné rozložení hmotnosti, přesné řízení a velmi čitelné chování v zatáčkách. Verze GTS stojí výkonnostně nad standardními variantami Caymana a přibližuje se charakterem modelům řady 911, přičemž si zachovává kompaktnější rozměry a nižší hmotnost.\n\nZ pohledu automechanika je Porsche Cayman GTS technicky propracovaný, ale relativně „čistý“ sportovní vůz bez zbytečných kompromisů. Motor uložený uprostřed má dobré chlazení a při dodržování servisních intervalů je považován za spolehlivý. Podvozek je naladěn sportovně, ale ne extrémně, což znamená rozumnou životnost brzd, pneumatik a dalších namáhaných komponent i při svižné jízdě. Oproti přeplňovaným nebo extrémně výkonným verzím klade Cayman GTS menší nároky na servis.\n\nMezi hlavní přednosti Porsche Cayman GTS patří vynikající ovladatelnost, nízká hmotnost, přesné řízení a velmi dobrý poměr mezi sportovností a použitelností. Nevýhodou je menší výkon oproti vrcholným verzím 911, omezený prostor a vyšší pořizovací cena v rámci segmentu. Porsche Cayman GTS je ideální volbou pro řidiče, kteří hledají čistý a technicky vyvážený sportovní vůz zaměřený především na radost z jízdy.', NULL),
(15, 'Porsche', '718 Boxster', '2.5 Turbo', 2018, 'Benzín', 257, 'Kabriolet', 2200000, 45000, '2025-10-22 07:48:37', 'Porsche 718 Boxster je otevřený sportovní roadster s motorem uloženým uprostřed, který klade důraz na radost z jízdy, vyváženost a přímý kontakt řidiče s vozem. Díky této koncepci nabízí velmi dobré rozložení hmotnosti a přesné chování v zatáčkách. Otevřená karoserie podtrhuje sportovní charakter vozu a umožňuje naplno vnímat zvuk motoru i celkový jízdní projev.\n\nZ pohledu automechanika je Porsche 718 Boxster technicky propracovaný, ale zároveň relativně spolehlivý sportovní automobil. Motor uložený uprostřed má efektivní chlazení a při dodržování servisních intervalů nevykazuje výrazné slabiny. Mechanismus skládací střechy vyžaduje pravidelnou kontrolu, avšak při správné údržbě funguje bezproblémově. Podvozek je naladěn sportovně, ale stále použitelně pro běžný provoz.\n\nMezi hlavní přednosti Porsche 718 Boxster patří výborná ovladatelnost, nízká hmotnost, otevřený jízdní zážitek a vysoká kvalita zpracování. Nevýhodou je omezená praktičnost, vyšší pořizovací cena a menší komfort při delších cestách se zavřenou střechou. Porsche 718 Boxster je ideální volbou pro řidiče, kteří hledají čistý sportovní roadster zaměřený především na zážitek z jízdy, nikoliv na maximální výkon.', NULL),
(16, 'Porsche', 'Panamera Turbo S', '4.0 V8', 2020, 'Benzín', 463, 'Sedan', 4200000, 25000, '2025-10-22 07:48:37', 'Porsche Panamera Turbo S je vrcholná výkonnostní varianta modelové řady Panamera, která kombinuje luxusní čtyřdveřový sedan s parametry plnohodnotného sportovního vozu. Díky výkonnému přeplňovanému osmiválci a pohonu všech kol nabízí extrémní akceleraci, vysokou maximální rychlost a mimořádnou stabilitu i při velmi dynamické jízdě. Panamera Turbo S dokazuje, že sportovní charakter značky Porsche lze úspěšně přenést i do komfortního a prostorného vozu.\n\nZ pohledu automechanika jde o technicky velmi komplexní automobil. Přeplňovaný V8 pracuje s vysokým výkonem a tepelným zatížením, což klade velké nároky na chlazení, mazání a kvalitu provozních kapalin. Aktivní podvozek, adaptivní vzduchové odpružení, výkonné brzdy a rozsáhlá elektronika zajišťují špičkové jízdní vlastnosti, ale zároveň zvyšují náročnost servisu. Při důsledném dodržování servisních intervalů je však Panamera Turbo S považována za spolehlivý vůz ve své třídě.\n\nMezi hlavní přednosti Porsche Panamera Turbo S patří kombinace extrémního výkonu, vysokého komfortu, luxusního interiéru a každodenní použitelnosti. Nevýhodou je velmi vysoká pořizovací cena, nákladný servis, vyšší hmotnost a spotřeba paliva. Porsche Panamera Turbo S je ideální volbou pro řidiče, kteří chtějí maximální výkon a sportovní projev, ale zároveň potřebují prostor a komfort prémiového sedanu.', NULL),
(17, 'Porsche', 'Taycan Turbo', 'Elektro', 2022, 'Elektro', 460, 'Sedan', 4500000, 18000, '2025-10-22 07:48:37', 'Porsche Taycan Turbo je vysoce výkonný elektrický sportovní sedan, který přenáší sportovní DNA značky Porsche do světa elektromobility. Přestože označení „Turbo“ u elektromobilu neodkazuje na přeplňování, vyjadřuje nejvyšší výkonnostní úroveň modelu. Díky dvojici elektromotorů a pohonu všech kol nabízí Taycan Turbo extrémně rychlou akceleraci, okamžitou odezvu na plyn a vysokou stabilitu v každé situaci.\n\nZ pohledu automechanika se jedná o technologicky velmi odlišný vůz oproti klasickým spalovacím Porsche. Elektrický pohon eliminuje složité mechanické části, jako jsou turbodmychadla nebo převodovky s mnoha stupni, což snižuje mechanické opotřebení. Naopak klíčovou roli hraje vysokonapěťová baterie, chlazení elektrických komponent a sofistikovaný systém řízení výkonu. Servis se více zaměřuje na diagnostiku, software a kontrolu elektroniky než na klasickou mechaniku.\n\nMezi hlavní přednosti Porsche Taycan Turbo patří extrémní akcelerace, tichý a plynulý chod, precizní jízdní vlastnosti a moderní technologie. Nevýhodou je vysoká pořizovací cena, vyšší hmotnost, omezený dojezd při dynamické jízdě a závislost na dostupnosti nabíjecí infrastruktury. Porsche Taycan Turbo je ideální volbou pro řidiče, kteří chtějí špičkový výkon a sportovní charakter Porsche v moderním elektrickém provedení.', NULL),
(18, 'Aston Martin', 'DB11', '5.2 V12', 2019, 'Benzín', 447, 'Coupé', 5900000, 20000, '2025-10-22 07:48:37', 'Aston Martin DB11 je luxusní sportovní vůz typu grand tourer, který kombinuje elegantní britský design s vysokým výkonem a komfortem pro dlouhé cesty. Model DB11 představuje novou generaci vozů Aston Martin a klade důraz na plynulost jízdy, kultivovaný projev a prestiž, spíše než na extrémní okruhový charakter. Díky motoru uloženému vpředu a pohonu zadních kol nabízí vyvážený jízdní projev a typický „GT feeling“.\n\nZ pohledu automechanika je Aston Martin DB11 technicky moderní, ale zároveň náročný automobil. Přeplňovaný motor pracuje s vysokým výkonem a teplotním zatížením, což klade důraz na kvalitní chlazení, olej a pravidelný servis. Vůz je vybaven pokročilou elektronikou a komfortními systémy, které zvyšují jízdní komfort, ale zároveň zvyšují složitost servisních zásahů. Při dodržování servisních intervalů je však DB11 schopen spolehlivého provozu v rámci své třídy.\n\nMezi hlavní přednosti Aston Martin DB11 patří nadčasový design, luxusní interiér, silný motor a vysoký komfort při dlouhých cestách. Nevýhodou je vysoká pořizovací cena, nákladný servis, vyšší hmotnost a menší zaměření na čistě sportovní jízdu oproti supersportům. Aston Martin DB11 je ideální volbou pro řidiče, kteří hledají elegantní a výkonné GT s důrazem na styl, prestiž a komfort.', NULL),
(19, 'Aston Martin', 'Vantage', '4.0 V8', 2021, 'Benzín', 375, 'Coupé', 5200000, 16000, '2025-10-22 07:48:37', 'Aston Martin Vantage je kompaktní sportovní vůz, který představuje nejdynamičtější a nejvíce řidičsky zaměřený model značky Aston Martin. Oproti luxusně laděnému DB11 působí Vantage agresivnějším dojmem a klade větší důraz na sportovní jízdu, přesné řízení a přímou odezvu. Motor uložený vpředu v kombinaci se zadním pohonem dává vozu klasickou sportovní koncepci a velmi vyvážený jízdní projev.\n\nZ pohledu automechanika je Aston Martin Vantage technicky moderní, ale náročný automobil. Přeplňovaný osmiválcový motor pracuje s vysokým výkonem a vyžaduje kvalitní palivo, olej a důsledné dodržování servisních intervalů. Podvozek je naladěn sportovně, což znamená vyšší namáhání brzd, pneumatik a podvozkových komponent při dynamické jízdě. Elektronické systémy řízení stability a podvozku výrazně pomáhají ovladatelnosti, ale zároveň zvyšují složitost servisu.\n\nMezi hlavní přednosti Aston Martin Vantage patří atraktivní a agresivní design, silný motor, velmi dobrá ovladatelnost a autentický sportovní charakter. Nevýhodou je vyšší pořizovací cena, nákladný servis, menší komfort na delších cestách a omezená praktičnost. Aston Martin Vantage je ideální volbou pro řidiče, kteří chtějí sportovní vůz s výrazným charakterem, prestiží a důrazem na zážitek z jízdy.', NULL),
(20, 'Aston Martin', 'DBS Superleggera', '5.2 V12', 2020, 'Benzín', 533, 'Coupé', 8200000, 12000, '2025-10-22 07:48:37', 'Aston Martin DBS Superleggera je vrcholný model značky Aston Martin, který spojuje luxusní charakter grand toureru s extrémním výkonem supersportu. Navazuje na legendární jméno DBS a představuje nejsilnější silniční Aston Martin své generace. Díky motoru uloženému vpředu, zadnímu pohonu a lehké konstrukci nabízí DBS Superleggera kombinaci vysoké rychlosti, elegance a suverénního jízdního projevu na dlouhých trasách.\n\nZ pohledu automechanika jde o technicky velmi náročný automobil. Přeplňovaný dvanáctiválcový motor pracuje s extrémním výkonem a vysokým tepelným zatížením, což klade maximální nároky na chlazení, mazání a kvalitu provozních kapalin. Podvozek je naladěn sportovně, ale stále komfortně pro cestování na dlouhé vzdálenosti. Rozsáhlé použití karbonových dílů snižuje hmotnost, avšak zároveň zvyšuje náklady na případné opravy a servis.\n\nMezi hlavní přednosti Aston Martin DBS Superleggera patří brutální výkon, charismatický projev dvanáctiválce, exkluzivní design a luxusní interiér. Nevýhodou je velmi vysoká pořizovací cena, extrémně nákladný servis, vyšší spotřeba paliva a omezená praktičnost v běžném provozu. DBS Superleggera je ideální volbou pro řidiče, kteří hledají ultimátní spojení prestiže, luxusu a výkonu v jednom z nejvýraznějších GT vozů současnosti.', NULL),
(21, 'McLaren', '720S', '4.0 V8 Biturbo', 2019, 'Benzín', 530, 'Coupé', 8900000, 11000, '2025-10-22 07:48:37', 'McLaren 720S je moderní britský supersport zaměřený na maximální výkon, nízkou hmotnost a technologickou vyspělost. Díky karbonovému monokoku a motoru uloženému uprostřed patří mezi nejlehčí a nejrychlejší vozy své kategorie. Přeplňovaný osmiválcový motor poskytuje extrémní akceleraci a velmi ostrý jízdní projev, přičemž 720S klade důraz především na rychlost a efektivitu, nikoli na luxus.\n\nZ pohledu automechanika je McLaren 720S technicky velmi sofistikovaný automobil. Karbonová konstrukce zajišťuje vysokou tuhost a nízkou hmotnost, ale zároveň výrazně zvyšuje náklady na opravy při poškození. Přeplňovaný motor pracuje s vysokým tlakem a teplotami, což klade vysoké nároky na chlazení, mazání a kvalitu paliva. Aktivní aerodynamika a hydraulicky řízený podvozek zajišťují špičkové jízdní vlastnosti, ale vyžadují precizní servis a bezchybný technický stav.\n\nMezi hlavní přednosti McLarenu 720S patří extrémní výkon, nízká hmotnost, precizní ovladatelnost a špičková aerodynamika. Nevýhodou je velmi nákladný servis, citlivost na poškození karoserie, menší zaměření na komfort a omezená praktičnost. McLaren 720S je ideální volbou pro řidiče, kteří hledají technicky vyspělý a extrémně rychlý supersport s důrazem na čistý výkon a moderní technologie.', NULL),
(22, 'McLaren', '600LT', '3.8 V8', 2019, 'Benzín', 441, 'Coupé', 7500000, 13000, '2025-10-22 07:48:37', 'McLaren 600LT je extrémně zaměřený supersport vycházející z modelu 570S, který byl upraven s jasným cílem – maximální výkon a jízdní efektivita na okruhu. Označení „LT“ (Longtail) odkazuje na závodní historii značky McLaren a znamená nižší hmotnost, agresivnější aerodynamiku a ostřejší naladění celého vozu. Motor je uložen uprostřed a spolu s pohonem zadních kol poskytuje velmi přímý a intenzivní jízdní zážitek.\n\nZ pohledu automechanika jde o technicky vysoce namáhaný automobil, který klade důraz na lehkost a výkon na úkor komfortu. Přeplňovaný osmiválcový motor pracuje s vysokými teplotami a tlakem, což vyžaduje kvalitní olej, pečlivé zahřívání a striktní dodržování servisních intervalů. Odlehčené komponenty, sportovní podvozek a výfuky vyvedené nahoru zlepšují výkon i chlazení, ale zároveň zvyšují hlučnost a nároky na údržbu.\n\nMezi hlavní přednosti McLarenu 600LT patří nízká hmotnost, extrémně přesné řízení, ostrý podvozek a silný okruhový charakter. Nevýhodou je minimální komfort, vyšší hlučnost, nákladný servis a omezená použitelnost pro běžný provoz. McLaren 600LT je ideální volbou pro nadšence, kteří chtějí téměř závodní supersport s homologací pro silniční provoz a jsou ochotni obětovat pohodlí ve prospěch maximálního zážitku z jízdy.', NULL),
(23, 'McLaren', 'Artura', '3.0 V6 Hybrid', 2022, 'Hybrid', 500, 'Coupé', 9500000, 6000, '2025-10-22 07:48:37', 'McLaren Artura představuje novou generaci supersportů značky McLaren a zároveň vstup do éry hybridního pohonu. Jedná se o sportovní vůz s motorem uloženým uprostřed, který kombinuje přeplňovaný šestiválcový motor s elektromotorem. Cílem modelu Artura není pouze maximální výkon, ale především vyšší efektivita, lepší odezva a moderní technologický přístup, aniž by byl potlačen sportovní charakter značky.\n\nZ pohledu automechanika je McLaren Artura technologicky velmi pokročilý a zároveň výrazně složitější než předchozí čistě spalovací modely. Hybridní systém přidává další chladicí okruhy, vysokonapěťové komponenty a náročnější diagnostiku. Na druhou stranu nový karbonový monokok a kompaktní konstrukce motoru přispívají k nízké hmotnosti a dobrému vyvážení vozu. Klíčová je pravidelná kontrola softwaru, bateriového systému a správné zacházení s vozem při studených startech.\n\nMezi hlavní přednosti McLarenu Artura patří moderní hybridní technologie, velmi rychlá odezva na plyn, nízká hmotnost a vyvážené jízdní vlastnosti. Nevýhodou je vyšší technická složitost, potenciálně nákladný servis, menší mechanická „syrovost“ oproti modelům LT a omezená praktičnost. McLaren Artura je ideální volbou pro řidiče, kteří chtějí moderní supersport kombinující výkon, technologie a částečně elektrický provoz, aniž by se vzdali sportovního DNA značky McLaren.', NULL),
(24, 'McLaren', 'GT', '4.0 V8', 2021, 'Benzín', 456, 'Coupé', 6700000, 7000, '2025-10-22 07:48:37', 'McLaren GT je sportovní vůz typu grand tourer, který představuje civilnější a komfortnější pojetí značky McLaren. Na rozdíl od ryze okruhově zaměřených supersportů klade důraz na pohodlí, použitelnost a cestování na dlouhé vzdálenosti, aniž by se vzdal vysokého výkonu a sportovního charakteru. Motor je uložen uprostřed a spolu se zadním pohonem nabízí vyvážený a jistý jízdní projev typický pro značku McLaren.\n\nZ pohledu automechanika je McLaren GT technicky vyspělý, ale méně extrémní než modely řady LT. Přeplňovaný osmiválcový motor je naladěn kultivovaněji, což snižuje jeho namáhání při běžném provozu. Podvozek je měkčí a komfortnější, což znamená menší opotřebení brzd a pneumatik při každodenním používání. Karbonová konstrukce zajišťuje nízkou hmotnost a tuhost, avšak případné opravy zůstávají finančně náročné.\n\nMezi hlavní přednosti McLarenu GT patří kombinace vysokého výkonu, komfortu, nízké hmotnosti a praktičnosti, včetně nadstandardního zavazadlového prostoru na poměry supersportů. Nevýhodou je vysoká pořizovací cena, nákladný servis a menší míra sportovní „syrovosti“ oproti modelům 600LT nebo 720S. McLaren GT je ideální volbou pro řidiče, kteří chtějí sportovní vůz McLaren, ale zároveň očekávají komfort a použitelnost klasického GT.', NULL),
(25, 'Audi', 'R8 V10 Plus', '5.2 V10', 2018, 'Benzín', 449, 'Coupé', 4200000, 30000, '2025-10-22 07:48:37', 'Audi R8 V10 Plus je vrcholná silniční verze modelu R8 a jeden z nejikoničtějších supersportů značky Audi. Vůz je poháněn atmosférickým desetiválcem uloženým uprostřed, který nabízí okamžitou odezvu na plyn, vysoké otáčky a charakteristický zvuk. Díky pohonu všech kol quattro poskytuje R8 V10 Plus výjimečnou trakci a stabilitu, což z něj činí velmi rychlý, ale zároveň čitelný a jistý supersport i mimo závodní okruh.\n\nZ pohledu automechanika je Audi R8 V10 Plus technicky vyspělý, ale překvapivě robustní automobil. Atmosférický V10 patří mezi mechanicky odolné jednotky, pokud je dodržováno správné zahřívání, kvalitní olej a pravidelný servis. Pohon quattro a dvouspojková převodovka zajišťují vysokou spolehlivost, avšak zvyšují složitost servisních zásahů. Oproti exotickým supersportům je R8 známá lepší každodenní použitelností a nižší poruchovostí.\n\nMezi hlavní přednosti Audi R8 V10 Plus patří výjimečný zvuk motoru, vysoký výkon, špičková trakce a velmi dobrá ovladatelnost. Nevýhodou je vyšší pořizovací cena, nákladný servis a menší exkluzivita oproti některým italským supersportům. Audi R8 V10 Plus je ideální volbou pro řidiče, kteří chtějí čistokrevný atmosférický supersport s vysokým výkonem, ale zároveň očekávají určitou míru praktičnosti a spolehlivosti.', '/assets/model/audi_r8_v10_plus.glb'),
(26, 'Audi', 'RS3', '2.5 TFSI', 2021, 'Benzín', 294, 'Hatchback', 1790000, 25000, '2025-10-22 07:48:37', 'Audi RS3 je kompaktní sportovní vůz, který patří mezi nejvýkonnější automobily ve své třídě. Typickým znakem modelu RS3 je přeplňovaný pětiválcový motor, jenž nabízí výrazný zvukový projev, vysoký výkon a velmi rychlou akceleraci. Díky pohonu všech kol quattro poskytuje RS3 výbornou trakci a jistotu v každodenním provozu i při dynamické jízdě.\n\nZ pohledu automechanika je Audi RS3 technicky vyspělý, ale relativně spolehlivý sportovní vůz, pokud je správně servisován. Pětiválcový motor je konstrukčně robustní, avšak pracuje s vysokým výkonem a plnicím tlakem, což klade nároky na kvalitní olej, palivo a pravidelné servisní intervaly. Pohon quattro a dvouspojková převodovka zvyšují stabilitu a použitelnost, ale zároveň přidávají na servisní složitosti a nákladech.\n\nMezi hlavní přednosti Audi RS3 patří extrémní výkon na kompaktní rozměry, výrazný zvuk motoru, vynikající trakce a dobrá každodenní použitelnost. Nevýhodou je vyšší hmotnost, nákladnější servis a menší zapojení řidiče ve srovnání s čistě zadokolkovými sportovními vozy. Audi RS3 je ideální volbou pro řidiče, kteří chtějí velmi rychlé, praktické a celoročně použitelné sportovní auto s výrazným charakterem.', NULL),
(27, 'Audi', 'RS4 Avant', '2.9 TFSI', 2020, 'Benzín', 331, 'Kombi', 2150000, 28000, '2025-10-22 07:48:37', 'Audi RS4 Avant je vysoce výkonné sportovní kombi, které kombinuje každodenní praktičnost s parametry plnohodnotného sportovního vozu. Díky přeplňovanému šestiválcovému motoru a pohonu všech kol quattro nabízí extrémní akceleraci, vysokou stabilitu a jistotu v jakýchkoli jízdních podmínkách. RS4 Avant je typickým představitelem filozofie značky Audi – nenápadný vzhled spojený s velmi vysokým výkonem.\n\nZ pohledu automechanika je Audi RS4 Avant technicky velmi vyspělý automobil. Přeplňovaný motor pracuje s vysokým výkonem a tepelným zatížením, což klade důraz na kvalitní olej, palivo a striktní dodržování servisních intervalů. Pohon quattro a sportovní automatická převodovka zajišťují výborný přenos výkonu, ale zároveň zvyšují složitost a náročnost servisu. Podvozek a brzdy jsou dimenzovány na vysoké zatížení, což se při dynamické jízdě projevuje rychlejším opotřebením spotřebních dílů.\n\nMezi hlavní přednosti Audi RS4 Avant patří kombinace vysokého výkonu, praktičnosti, komfortu a celoroční použitelnosti. Nevýhodou je vyšší hmotnost, nákladný servis a menší „řidičská syrovost“ oproti čistě sportovním modelům. Audi RS4 Avant je ideální volbou pro řidiče, kteří chtějí extrémně rychlé auto, ale zároveň potřebují prostor, komfort a univerzálnost rodinného vozu.', NULL),
(28, 'Audi', 'RS5', '2.9 TFSI', 2020, 'Benzín', 331, 'Coupé', 2250000, 23000, '2025-10-22 07:48:37', 'Audi RS5 je sportovní kupé (případně Sportback), které spojuje elegantní design s velmi vysokým výkonem a každodenní použitelností. Oproti praktičtější RS4 Avant je RS5 více zaměřena na sportovní projev a vizuální dojem, přičemž si zachovává typickou technickou vyspělost značky Audi. Přeplňovaný šestiválcový motor v kombinaci s pohonem všech kol quattro zajišťuje rychlou akceleraci, vysokou stabilitu a jistotu i při dynamické jízdě.\n\nZ pohledu automechanika je Audi RS5 technicky velmi sofistikovaný automobil. Přeplňovaný motor pracuje s vysokým výkonem a tepelným zatížením, což vyžaduje kvalitní olej, palivo a striktní dodržování servisních intervalů. Pohon quattro a sportovní automatická převodovka zajišťují efektivní přenos výkonu, ale zároveň zvyšují složitost a náročnost servisu. Podvozek a brzdy jsou dimenzovány na sportovní jízdu, což se může projevit rychlejším opotřebením při častém dynamickém využívání.\n\nMezi hlavní přednosti Audi RS5 patří atraktivní design, vysoký výkon, výborná trakce a dobrá použitelnost v běžném provozu. Nevýhodou je vyšší hmotnost, nákladný servis a menší zapojení řidiče ve srovnání s čistě zadokolkovými sportovními vozy. Audi RS5 je ideální volbou pro řidiče, kteří chtějí rychlé a stylové sportovní auto, ale zároveň očekávají komfort a univerzálnost.', NULL),
(29, 'Audi', 'RS6 Avant', '4.0 TFSI', 2021, 'Benzín', 441, 'Kombi', 3800000, 22000, '2025-10-22 07:48:37', 'Audi RS6 Avant je ikonické sportovní kombi, které spojuje extrémní výkon supersportu s praktičností rodinného vozu. Díky přeplňovanému osmiválcovému motoru a pohonu všech kol quattro nabízí mimořádnou akceleraci, vysokou stabilitu a jistotu v každých podmínkách. RS6 Avant působí nenápadně, ale svými parametry se řadí mezi nejrychlejší vozy své kategorie.\n\nZ pohledu automechanika je Audi RS6 Avant technicky velmi komplexní automobil. Výkonný V8 pracuje s vysokým tepelným i mechanickým zatížením, což klade velké nároky na chlazení, mazání a kvalitu paliva. Pohon quattro, sportovní automatická převodovka, adaptivní podvozek a výkonné brzdy zajišťují špičkové jízdní vlastnosti, ale zároveň zvyšují náročnost a cenu servisu. Při pravidelné údržbě je však RS6 schopná spolehlivého provozu i při dynamickém stylu jízdy.\n\nMezi hlavní přednosti Audi RS6 Avant patří brutální výkon, vynikající trakce, vysoký komfort a plná každodenní použitelnost včetně velkého zavazadlového prostoru. Nevýhodou je vysoká pořizovací cena, nákladný servis, vyšší hmotnost a spotřeba paliva. Audi RS6 Avant je ideální volbou pro řidiče, kteří chtějí extrémně rychlé auto bez nutnosti obětovat praktičnost a komfort.', NULL),
(30, 'Audi', 'RS7 Sportback', '4.0 TFSI', 2021, 'Benzín', 441, 'Sedan', 4100000, 20000, '2025-10-22 07:48:37', 'Audi RS7 Sportback je vysoce výkonný sportovní liftback, který spojuje elegantní design čtyřdveřového kupé s extrémním výkonem. Díky přeplňovanému osmiválcovému motoru a pohonu všech kol quattro nabízí mimořádnou akceleraci, vysokou stabilitu a suverénní jízdní projev i při velmi vysokých rychlostech. RS7 působí luxusně a nenápadně, ale svými parametry se řadí mezi nejrychlejší vozy ve své třídě.\n\nZ pohledu automechanika je Audi RS7 Sportback technicky velmi komplexní automobil. Výkonný V8 pracuje s vysokým tepelným zatížením, což klade důraz na kvalitní olej, palivo a striktní dodržování servisních intervalů. Pohon quattro, sportovní automatická převodovka, adaptivní podvozek a výkonné brzdy zajišťují špičkové jízdní vlastnosti, ale zároveň zvyšují náročnost a cenu servisu. Při správné údržbě je však RS7 schopna dlouhodobě spolehlivého provozu.\n\nMezi hlavní přednosti Audi RS7 Sportback patří kombinace extrémního výkonu, luxusního interiéru, komfortu a každodenní použitelnosti. Nevýhodou je vysoká pořizovací cena, nákladný servis, vyšší hmotnost a spotřeba paliva. Audi RS7 Sportback je ideální volbou pro řidiče, kteří chtějí supersportovní výkon v elegantním a praktickém balení bez kompromisů v oblasti komfortu.', NULL),
(31, 'Audi', 'TT RS', '2.5 TFSI', 2019, 'Benzín', 294, 'Coupé', 1750000, 27000, '2025-10-22 07:48:37', 'Audi TT RS je kompaktní sportovní vůz, který vyniká jedinečnou kombinací nízké hmotnosti, vysokého výkonu a charakteristického pětiválcového motoru. Díky přeplňovanému pětiválci a pohonu všech kol quattro nabízí extrémně rychlou akceleraci, výbornou trakci a jistotu i při dynamické jízdě. TT RS patří mezi nejrychlejší vozy ve své třídě a zároveň si zachovává každodenní použitelnost.\n\nZ pohledu automechanika je Audi TT RS technicky vyspělý, ale relativně robustní sportovní automobil. Pětiválcový motor je známý svou odolností, avšak pracuje s vysokým výkonem a plnicím tlakem, což klade důraz na kvalitní olej, palivo a pravidelný servis. Pohon quattro a dvouspojková převodovka zajišťují efektivní přenos výkonu, ale zároveň zvyšují složitost a náročnost servisních zásahů. Podvozek a brzdy jsou dimenzovány na sportovní jízdu, což se může projevit rychlejším opotřebením při častém dynamickém využívání.\n\nMezi hlavní přednosti Audi TT RS patří extrémní výkon na kompaktní rozměry, výrazný zvuk pětiválce, špičková trakce a dobrá použitelnost v běžném provozu. Nevýhodou je omezený vnitřní prostor, vyšší pořizovací cena a menší zapojení řidiče ve srovnání s čistě zadokolkovými sportovními vozy. Audi TT RS je ideální volbou pro řidiče, kteří chtějí velmi rychlé a zábavné sportovní auto s jedinečným charakterem a typickým zvukem.', NULL),
(32, 'BMW', 'M2 Competition', '3.0 Twin Turbo', 2019, 'Benzín', 302, 'Coupé', 1800000, 32000, '2025-10-22 07:48:37', 'BMW M2 Competition je kompaktní sportovní kupé, které patří mezi nejčistší řidičské vozy značky BMW. Oproti standardní M2 přináší výkonnější motor, tužší podvozek a celkově ostřejší charakter. Díky přeplňovanému šestiválcovému motoru a pohonu zadních kol nabízí M2 Competition velmi intenzivní jízdní zážitek, přímou odezvu a typickou zábavu, kterou od modelů BMW M řidiči očekávají.\n\nZ pohledu automechanika je BMW M2 Competition technicky robustní, ale náročné auto. Výkonný šestiválec pracuje s vysokým plnicím tlakem a teplotami, což klade důraz na kvalitní olej, pravidelný servis a správné zacházení, zejména při studeném motoru. Zadní pohon a mechanický samosvorný diferenciál poskytují skvělý jízdní projev, ale zároveň kladou vyšší nároky na pneumatiky a brzdy při sportovní jízdě. Celkově jde o vůz, který při správné údržbě nabízí velmi dobrou spolehlivost.\n\nMezi hlavní přednosti BMW M2 Competition patří silný motor, pohon zadních kol, přesné řízení a velmi zábavný charakter. Nevýhodou je tvrdší podvozek, vyšší spotřeba při dynamické jízdě a omezená praktičnost oproti běžným modelům řady 2. BMW M2 Competition je ideální volbou pro řidiče, kteří hledají kompaktní, nekompromisní sportovní auto zaměřené především na radost z jízdy.', NULL),
(33, 'BMW', 'M3 Competition', '3.0 Twin Turbo', 2021, 'Benzín', 375, 'Sedan', 2600000, 20000, '2025-10-22 07:48:37', 'BMW M3 Competition je vysoce výkonný sportovní sedan, který představuje vrchol řady BMW M v kombinaci výkonu, praktičnosti a moderních technologií. Oproti standardní M3 nabízí vyšší výkon, ostřejší nastavení motoru a sportovnější charakter. Přeplňovaný řadový šestiválec v kombinaci se sportovní automatickou převodovkou poskytuje mimořádně rychlou akceleraci a silný zátah v celém spektru otáček, přičemž vůz zůstává plně použitelný pro každodenní provoz.\n\nZ pohledu automechanika je BMW M3 Competition technicky velmi vyspělý, ale také náročný automobil. Výkonný šestiválcový motor pracuje s vysokým plnicím tlakem a tepelným zatížením, což klade důraz na kvalitní olej, palivo a přísné dodržování servisních intervalů. Podvozek, brzdy a samosvorný diferenciál jsou konstruovány pro vysoké zatížení, což se při sportovní jízdě může projevit rychlejším opotřebením spotřebních dílů. Při správné údržbě však M3 Competition nabízí velmi dobrou spolehlivost.\n\nMezi hlavní přednosti BMW M3 Competition patří extrémní výkon, přesné řízení, vysoká stabilita a kombinace sportovního charakteru s praktičností čtyřdveřového vozu. Nevýhodou je vyšší hmotnost, nákladný servis a tvrdší podvozek oproti běžným sedanům. BMW M3 Competition je ideální volbou pro řidiče, kteří chtějí plnohodnotné sportovní auto schopné ostré jízdy, ale zároveň potřebují prostor a každodenní využitelnost.', NULL),
(34, 'BMW', 'M4 G82', '3.0 Twin Turbo', 2022, 'Benzín', 375, 'Coupé', 2950000, 15000, '2025-10-22 07:48:37', 'BMW M4 G82 je moderní sportovní kupé, které představuje jednu z nejostřejších silničních variant řady BMW M. Oproti předchozí generaci přináší výrazně agresivnější design, vyšší výkon a technicky vyspělejší podvozek. Přeplňovaný řadový šestiválec nabízí silný a plynulý zátah v celém spektru otáček, zatímco pohon zadních kol (případně xDrive) zajišťuje velmi dynamický a zábavný jízdní projev.\n\nZ pohledu automechanika je BMW M4 G82 technicky velmi komplexní automobil. Výkonný šestiválcový motor pracuje s vysokým plnicím tlakem a teplotami, což klade důraz na kvalitní olej, palivo a striktní dodržování servisních intervalů. Podvozek, brzdy a samosvorný diferenciál jsou konstruovány na vysoké zatížení, což se při sportovní jízdě projevuje vyšším opotřebením pneumatik a brzd. Moderní elektronické systémy výrazně zvyšují ovladatelnost, ale zároveň zvyšují náročnost servisních zásahů.\n\nMezi hlavní přednosti BMW M4 G82 patří extrémní výkon, přesné řízení, velmi dobrá stabilita a výrazný sportovní charakter. Nevýhodou je vyšší hmotnost, nákladný servis a menší praktičnost oproti čtyřdveřové M3. BMW M4 G82 je ideální volbou pro řidiče, kteří chtějí čistokrevné sportovní kupé s vysokým výkonem a moderními technologiemi, zaměřené především na radost z jízdy.', NULL),
(35, 'BMW', 'M5 F90', '4.4 V8', 2020, 'Benzín', 460, 'Sedan', 3500000, 22000, '2025-10-22 07:48:37', 'BMW M5 F90 je extrémně výkonný sportovní sedan, který posunul pojem „rychlá limuzína“ na novou úroveň. Jako první M5 v historii využívá pohon všech kol M xDrive, díky čemuž kombinuje brutální výkon s výjimečnou trakcí a stabilitou. Přeplňovaný osmiválcový motor nabízí masivní zátah v celém spektru otáček a umožňuje vozu dosahovat dynamiky srovnatelné se supersporty, přesto si zachovává plnou každodenní použitelnost.\n\nZ pohledu automechanika je BMW M5 F90 technicky velmi komplexní automobil. Výkonný V8 pracuje s vysokým tepelným i mechanickým zatížením, což klade maximální nároky na chlazení, mazání a kvalitu provozních kapalin. Pohon M xDrive, aktivní diferenciál, adaptivní podvozek a výkonné brzdy zajišťují špičkové jízdní vlastnosti, ale zároveň výrazně zvyšují náročnost a cenu servisu. Při důsledném dodržování servisních intervalů je však M5 F90 považována za velmi schopný a relativně spolehlivý vůz ve své třídě.\n\nMezi hlavní přednosti BMW M5 F90 patří extrémní výkon, vynikající trakce, vysoký komfort a schopnost zvládat jak klidnou jízdu, tak agresivní sportovní styl. Nevýhodou je vysoká pořizovací cena, nákladný servis, vyšší hmotnost a spotřeba paliva. BMW M5 F90 je ideální volbou pro řidiče, kteří chtějí absolutní výkon supersportu v praktickém a luxusním balení čtyřdveřového sedanu.', NULL);
INSERT INTO `cars` (`id`, `brand`, `model`, `variant`, `year`, `fuel`, `power_kw`, `body`, `price`, `mileage`, `created_at`, `description`, `model_3d`) VALUES
(36, 'BMW', 'M8 Competition', '4.4 V8', 2021, 'Benzín', 460, 'Coupé', 4200000, 16000, '2025-10-22 07:48:37', 'BMW M8 Competition je vrcholný sportovní model řady 8, který kombinuje extrémní výkon s luxusem a elegantním designem. Jde o jedno z nejsilnějších silničních BMW vůbec, které díky přeplňovanému osmiválcovému motoru a pohonu všech kol M xDrive nabízí brutální akceleraci, vysokou stabilitu a suverénní jízdní projev. M8 Competition působí jako luxusní gran turismo, ale svými dynamickými schopnostmi se bez problému řadí mezi supersedany a supersporty.\n\nZ pohledu automechanika je BMW M8 Competition technicky velmi komplexní automobil. Výkonný V8 pracuje s vysokým tepelným i mechanickým zatížením, což vyžaduje kvalitní olej, palivo a důsledné dodržování servisních intervalů. Pohon M xDrive, aktivní diferenciál, adaptivní podvozek a výkonné brzdy zajišťují špičkové jízdní vlastnosti, ale zároveň výrazně zvyšují náročnost a cenu servisu. Při správné údržbě je však M8 Competition schopna dlouhodobě spolehlivého provozu.\n\nMezi hlavní přednosti BMW M8 Competition patří extrémní výkon, vysoký komfort, luxusní interiér a jistota pohonu všech kol. Nevýhodou je velmi vysoká pořizovací cena, nákladný servis, vyšší hmotnost a spotřeba paliva. BMW M8 Competition je ideální volbou pro řidiče, kteří chtějí spojení luxusního GT vozu s výkonem supersportu a nechtějí dělat kompromisy mezi komfortem a dynamikou.', NULL),
(37, 'BMW', 'Z4 M40i', '3.0 Turbo', 2020, 'Benzín', 250, 'Kabriolet', 1650000, 24000, '2025-10-22 07:48:37', 'BMW Z4 M40i je sportovní roadster, který kombinuje otevřenou karoserii s vysokým výkonem a typickým řidičským projevem značky BMW. Díky přeplňovanému řadovému šestiválci a pohonu zadních kol nabízí velmi dynamickou jízdu, okamžitou odezvu na plyn a výrazný zvukový projev. Z4 M40i je zaměřena především na zábavu za volantem a radost z otevřené jízdy, nikoliv na maximální praktičnost.\n\nZ pohledu automechanika je BMW Z4 M40i technicky vyspělý, ale relativně spolehlivý sportovní vůz. Šestiválcový motor je považován za robustní jednotku, pokud je dodržován pravidelný servis, kvalitní olej a správné zahřívání. Podvozek je naladěn sportovně, avšak stále komfortně pro běžné silnice. Mechanismus plátěné střechy je konstrukčně jednodušší než pevné střechy starších generací, ale vyžaduje pravidelnou kontrolu a údržbu.\n\nMezi hlavní přednosti BMW Z4 M40i patří silný motor, pohon zadních kol, otevřený jízdní zážitek a velmi dobré jízdní vlastnosti. Nevýhodou je omezená praktičnost, menší zavazadlový prostor, vyšší pořizovací cena a vyšší hlučnost při dálničních rychlostech. BMW Z4 M40i je ideální volbou pro řidiče, kteří chtějí sportovní roadster s výrazným výkonem a čistým řidičským charakterem.', NULL),
(38, 'Mercedes-AMG', 'A45 S', '2.0 Turbo', 2021, 'Benzín', 310, 'Hatchback', 1890000, 23000, '2025-10-22 07:48:37', 'Mercedes-AMG A45 S je extrémně výkonný sportovní hatchback, který posouvá hranice své třídy. Je poháněn přeplňovaným čtyřválcovým motorem, jenž patří mezi nejsilnější sériově vyráběné čtyřválce na světě. V kombinaci s pohonem všech kol 4MATIC+ nabízí A45 S mimořádnou akceleraci, vysokou stabilitu a velmi jistý jízdní projev i při agresivní jízdě.\n\nZ pohledu automechanika jde o technicky velmi sofistikovaný automobil. Vysoce výkonný motor pracuje s extrémním plnicím tlakem a teplotami, což klade maximální nároky na chlazení, mazání a kvalitu provozních kapalin. Pohon 4MATIC+ s aktivním rozdělováním výkonu mezi zadní kola výrazně zlepšuje ovladatelnost, ale zároveň zvyšuje složitost a náročnost servisu. Při striktním dodržování servisních intervalů je však A45 S považována za spolehlivý vůz ve své kategorii.\n\nMezi hlavní přednosti Mercedes-AMG A45 S patří extrémní výkon na kompaktní rozměry, špičková trakce, moderní technologie a velmi rychlá akcelerace. Nevýhodou je tvrdší podvozek, nákladný servis a menší mechanická „čitelnost“ oproti zadokolkovým sportovním vozům. Mercedes-AMG A45 S je ideální volbou pro řidiče, kteří chtějí maximální výkon a technologie v praktickém hatchbacku vhodném i pro každodenní použití.', NULL),
(39, 'Mercedes-AMG', 'C63 S', '4.0 V8', 2019, 'Benzín', 375, 'Sedan', 2700000, 26000, '2025-10-22 07:48:37', 'Mercedes-AMG C63 S je vysoce výkonný sportovní vůz, který představuje tradiční pojetí modelů AMG – silný motor, pohon zadních kol a výrazný charakter. Verze „S“ stojí na vrcholu nabídky a nabízí ještě ostřejší naladění podvozku, řízení i pohonného ústrojí. Atmosféru vozu určuje především přeplňovaný osmiválcový motor, který poskytuje masivní zátah a typický hluboký zvuk, jenž je pro AMG charakteristický.\n\nZ pohledu automechanika je Mercedes-AMG C63 S technicky náročný automobil, který klade vysoké nároky na údržbu. Výkonný V8 pracuje s vysokým tepelným zatížením, což vyžaduje kvalitní olej, palivo a striktní dodržování servisních intervalů. Zadní pohon a vysoký výkon znamenají zvýšené opotřebení pneumatik a brzd při sportovní jízdě, zatímco elektronické systémy a adaptivní podvozek zvyšují složitost servisních zásahů. Při správné údržbě je však C63 S považována za velmi odolný a mechanicky poctivý sportovní vůz.\n\nMezi hlavní přednosti Mercedes-AMG C63 S patří brutální výkon, charismatický zvuk osmiválce, sportovní charakter a vysoká úroveň zpracování. Nevýhodou je vysoká spotřeba paliva, nákladný servis, tvrdší podvozek a omezená trakce oproti čtyřkolkám. Mercedes-AMG C63 S je ideální volbou pro řidiče, kteří chtějí klasický, emotivní sportovní sedan nebo kupé s důrazem na výkon a zážitek z jízdy.', NULL),
(40, 'Mercedes-AMG', 'E63 S', '4.0 V8', 2020, 'Benzín', 450, 'Sedan', 3400000, 21000, '2025-10-22 07:48:37', 'Mercedes-AMG E63 S je extrémně výkonný sportovní sedan (nebo kombi), který kombinuje luxus vyšší střední třídy s dynamikou supersportu. Pod kapotou se nachází přeplňovaný osmiválcový motor, který ve spojení s pohonem všech kol 4MATIC+ nabízí brutální akceleraci, vysokou stabilitu a jistotu přenosu výkonu za všech podmínek. E63 S patří mezi nejrychlejší sériově vyráběné čtyřdveřové vozy na světě.\n\nZ pohledu automechanika je Mercedes-AMG E63 S technicky velmi komplexní automobil. Výkonný V8 pracuje s extrémním tepelným i mechanickým zatížením, což klade vysoké nároky na chlazení, mazání a kvalitu provozních kapalin. Pohon 4MATIC+ s možností plně zadního pohonu, aktivní diferenciál, adaptivní podvozek a výkonné brzdy zajišťují špičkové jízdní vlastnosti, ale zároveň výrazně zvyšují náročnost a cenu servisu. Při důsledné údržbě je však E63 S považována za velmi odolný a spolehlivý vůz ve své kategorii.\n\nMezi hlavní přednosti Mercedes-AMG E63 S patří extrémní výkon, vynikající trakce, vysoký komfort a schopnost fungovat jako luxusní manažerský vůz i jako velmi ostré sportovní auto. Nevýhodou je vysoká pořizovací cena, nákladný servis, vyšší hmotnost a spotřeba paliva. Mercedes-AMG E63 S je ideální volbou pro řidiče, kteří chtějí absolutní výkon, prestiž a praktičnost bez kompromisů.', NULL),
(41, 'Mercedes-AMG', 'GT R', '4.0 V8', 2018, 'Benzín', 430, 'Coupé', 6200000, 18000, '2025-10-22 07:48:37', 'Mercedes-AMG GT R je extrémně sportovní kupé vyvinuté s jasným cílem – maximální výkon a ovladatelnost na závodním okruhu. Oproti standardnímu AMG GT je verze „R“ výrazně odlehčená, agresivně aerodynamicky upravená a technicky přizpůsobená pro ostrou jízdu. Přeplňovaný osmiválcový motor uložený vpředu v kombinaci se zadním pohonem poskytuje brutální zátah, výrazný zvuk a velmi syrový jízdní projev.\n\nZ pohledu automechanika jde o technicky vysoce namáhaný automobil, který vyžaduje precizní údržbu a respekt. Výkonný V8 pracuje s vysokým tepelným zatížením, což klade maximální nároky na chlazení, mazání a kvalitu provozních kapalin. Aktivní aerodynamika, řízení zadní nápravy, tuhý podvozek a výkonné brzdy zajišťují špičkovou stabilitu a přesnost, ale zároveň výrazně zvyšují náročnost servisu a provozu. Tento vůz není stavěn na kompromisy ani každodenní používání.\n\nMezi hlavní přednosti Mercedes-AMG GT R patří extrémní výkon, vynikající ovladatelnost, okruhový charakter a ikonický design. Nevýhodou je minimální komfort, velmi tvrdý podvozek, vysoká hlučnost, nákladný servis a omezená použitelnost v běžném provozu. Mercedes-AMG GT R je ideální volbou pro zkušené řidiče a nadšence, kteří hledají silniční vůz co nejblíže závodní technice.', NULL),
(42, 'Mercedes-AMG', 'SL63', '4.0 V8', 2022, 'Benzín', 430, 'Kabriolet', 5900000, 9000, '2025-10-22 07:48:37', 'Mercedes-AMG SL 63 je luxusní sportovní roadster, který kombinuje otevřenou karoserii s extrémním výkonem a vysokým komfortem. Model SL se v této generaci vrací ke sportovním kořenům značky AMG a spojuje elegantní design, moderní technologie a dynamiku plnohodnotného sportovního vozu. Díky přeplňovanému osmiválcovému motoru a pohonu všech kol 4MATIC+ nabízí SL 63 mimořádnou akceleraci a stabilitu i při velmi svižné jízdě.\n\nZ pohledu automechanika je Mercedes-AMG SL 63 technicky velmi komplexní automobil. Výkonný V8 pracuje s vysokým tepelným i mechanickým zatížením, což klade vysoké nároky na chlazení, mazání a kvalitu provozních kapalin. Podvozek s aktivním řízením, adaptivní tlumiče, pohon všech kol a mechanismus plátěné střechy zvyšují jízdní komfort i sportovní schopnosti, ale zároveň výrazně zvyšují náročnost a cenu servisu. Při pravidelné údržbě je však SL 63 schopna spolehlivého provozu i při dynamickém stylu jízdy.\n\nMezi hlavní přednosti Mercedes-AMG SL 63 patří kombinace extrémního výkonu, otevřeného jízdního zážitku, luxusního interiéru a každodenní použitelnosti. Nevýhodou je velmi vysoká pořizovací cena, nákladný servis, vyšší hmotnost a spotřeba paliva. Mercedes-AMG SL 63 je ideální volbou pro řidiče, kteří chtějí sportovní roadster s výkonem supersportu, ale zároveň očekávají komfort a prestiž luxusního vozu.', NULL),
(43, 'Mercedes-AMG', 'GT 63 S', '4.0 V8', 2021, 'Benzín', 470, 'Sedan', 6900000, 12000, '2025-10-22 07:48:37', 'Mercedes-AMG GT 63 S je extrémně výkonný čtyřdveřový sportovní vůz, který spojuje praktičnost luxusního sedanu s dynamikou supersportu. Díky přeplňovanému osmiválcovému motoru a pohonu všech kol 4MATIC+ nabízí brutální akceleraci, vysokou stabilitu a jistotu přenosu výkonu i při velmi vysokých rychlostech. GT 63 S je technicky blízký modelům AMG GT a představuje jeden z nejvýkonnějších čtyřdveřových automobilů na trhu.\n\nZ pohledu automechanika je Mercedes-AMG GT 63 S technicky velmi komplexní automobil. Výkonný V8 pracuje s extrémním tepelným a mechanickým zatížením, což klade maximální nároky na chlazení, mazání a kvalitu provozních kapalin. Pohon 4MATIC+ s variabilním rozdělováním výkonu, aktivní podvozek, řízení zadní nápravy a výkonné brzdy zajišťují špičkové jízdní vlastnosti, ale zároveň výrazně zvyšují náročnost a cenu servisu. Při důsledné údržbě je však vůz schopen dlouhodobě spolehlivého provozu.\n\nMezi hlavní přednosti Mercedes-AMG GT 63 S patří extrémní výkon, vynikající trakce, luxusní interiér a překvapivá každodenní použitelnost. Nevýhodou je velmi vysoká pořizovací cena, nákladný servis, vyšší hmotnost a spotřeba paliva. Mercedes-AMG GT 63 S je ideální volbou pro řidiče, kteří chtějí výkon supersportu v elegantním čtyřdveřovém provedení bez nutnosti obětovat komfort a praktičnost.', NULL),
(44, 'Nissan', 'GT-R', '3.8 Twin Turbo', 2020, 'Benzín', 419, 'Coupé', 2900000, 30000, '2025-10-22 07:48:37', 'Nissan GT-R je legendární japonský supersport přezdívaný „Godzilla“, který se proslavil schopností konkurovat výrazně dražším evropským vozům. Díky přeplňovanému šestiválcovému motoru, pokročilému pohonu všech kol a sofistikované elektronice nabízí GT-R extrémní akceleraci, vysokou stabilitu a mimořádnou efektivitu přenosu výkonu na silnici. Je to vůz zaměřený především na rychlost, přesnost a technickou dokonalost.\n\nZ pohledu automechanika je Nissan GT-R technicky velmi komplexní automobil. Přeplňovaný motor pracuje s vysokým výkonem a tlakem, což klade důraz na kvalitní olej, palivo a striktní dodržování servisních intervalů. Dvouspojková převodovka, pohon všech kol ATTESA E-TS a pokročilé řízení trakce zajišťují špičkové jízdní vlastnosti, ale zároveň výrazně zvyšují náročnost a cenu servisu. Při správné údržbě je však GT-R považován za mechanicky velmi odolný supersport.\n\nMezi hlavní přednosti Nissan GT-R patří brutální výkon, vynikající trakce, extrémní rychlost na silnici i okruhu a vysoký poměr výkon/cena. Nevýhodou je vyšší hmotnost, nákladný servis, méně luxusní interiér a vyšší spotřeba paliva. Nissan GT-R je ideální volbou pro řidiče, kteří hledají technicky vyspělý supersport s nekompromisním výkonem a legendární pověstí.', NULL),
(45, 'Nissan', '370Z Nismo', '3.7 V6', 2018, 'Benzín', 253, 'Coupé', 1450000, 45000, '2025-10-22 07:48:37', 'Nissan 370Z Nismo je sportovní kupé s klasickou koncepcí motoru vpředu a pohonu zadních kol, které reprezentuje čistý, mechanický přístup ke sportovní jízdě. Oproti standardní verzi 370Z přináší edice Nismo ostřejší naladění motoru, tužší podvozek, lepší brzdy a výraznější aerodynamické prvky. Atmosférický šestiválcový motor nabízí lineární nástup výkonu, vysoké otáčky a charakteristický zvuk, který je dnes u moderních aut stále vzácnější.\n\nZ pohledu automechanika je Nissan 370Z Nismo relativně jednoduchý a poctivý sportovní vůz. Atmosférický V6 je považován za mechanicky odolný, pokud je dodržována pravidelná údržba, kvalitní olej a správné zahřívání. Absence turbodmychadel a složité elektroniky znamená nižší riziko drahých poruch oproti moderním přeplňovaným sportovním vozům. Zadní pohon a samosvorný diferenciál však kladou vyšší nároky na pneumatiky a řidičské schopnosti při dynamické jízdě.\n\nMezi hlavní přednosti Nissan 370Z Nismo patří autentický sportovní charakter, atmosférický motor, přesná odezva řízení a jednoduchá technika. Nevýhodou je horší každodenní použitelnost, vyšší spotřeba, omezený vnitřní prostor a méně moderní interiér. Nissan 370Z Nismo je ideální volbou pro nadšence, kteří hledají čisté sportovní auto zaměřené na radost z jízdy, nikoliv na komfort nebo nejnovější technologie.', NULL),
(46, 'Nissan', 'Z Proto', '3.0 Twin Turbo', 2022, 'Benzín', 298, 'Coupé', 1900000, 8000, '2025-10-22 07:48:37', 'Nissan Z Proto je koncept sportovního kupé, který předznamenal návrat legendární řady Z v moderním pojetí. Designově spojuje klasické prvky starších generací, jako jsou dlouhá kapota a jednoduché zadní svítilny, s moderními technologiemi a agresivnějším vzhledem. Z Proto jasně ukazuje zaměření na řidičský zážitek a zachování tradiční koncepce motoru vpředu a pohonu zadních kol.\n\nZ pohledu automechanika představuje Nissan Z Proto posun od atmosférických motorů k modernímu přeplňovanému šestiválci, který nabízí vyšší výkon a lepší efektivitu. Technicky jde o sportovní vůz s důrazem na mechanickou poctivost, jednoduchou koncepci a minimální kompromisy ve prospěch komfortu. Očekává se robustní konstrukce motoru a podvozku, které navazují na osvědčenou techniku předchozích modelů řady Z, avšak s modernější elektronikou a bezpečnostními systémy.\n\nMezi hlavní přednosti Nissan Z Proto patří návrat ke klasickému sportovnímu charakteru, atraktivní retro-moderní design, silný šestiválcový motor a pohon zadních kol. Nevýhodou je omezená praktičnost, menší zaměření na komfort a skutečnost, že jde původně o koncept, nikoliv plně produkční model. Nissan Z Proto je ideální volbou pro nadšence, kteří oceňují historii značky Nissan a chtějí moderní sportovní vůz s tradičním charakterem.', NULL),
(47, 'Toyota', 'Supra GR', '3.0 Turbo', 2021, 'Benzín', 250, 'Coupé', 1750000, 15000, '2025-10-22 07:48:37', 'Toyota GR Supra je moderní sportovní kupé, které navazuje na legendární jméno Supra a vrací značku Toyota zpět mezi čistokrevná sportovní auta. Vůz vznikl ve spolupráci s BMW, což se odráží především v použité technice, ale celkový charakter je jasně zaměřen na řidičský zážitek. Díky motoru uloženému vpředu a pohonu zadních kol nabízí GR Supra velmi vyvážené jízdní vlastnosti, rychlou akceleraci a zábavný projev.\n\nZ pohledu automechanika je Toyota GR Supra technicky vyspělý a zároveň relativně spolehlivý sportovní vůz. Přeplňovaný řadový šestiválec (u slabších verzí čtyřválec) je osvědčená jednotka, která při pravidelném servisu a kvalitních provozních kapalinách vykazuje dobrou životnost. Podvozek je naladěn sportovně, ale ne extrémně, což znamená rozumné opotřebení brzd a pneumatik při běžném provozu. Moderní elektronika zlepšuje ovladatelnost, ale zároveň zvyšuje náročnost diagnostiky a servisu.\n\nMezi hlavní přednosti Toyoty GR Supra patří silný motor, pohon zadních kol, výborná ovladatelnost a atraktivní sportovní design. Nevýhodou je omezená praktičnost, menší vnitřní prostor, vyšší pořizovací cena a fakt, že vůz sdílí techniku s BMW, což nemusí vyhovovat všem fanouškům značky. Toyota GR Supra je ideální volbou pro řidiče, kteří chtějí moderní sportovní auto s klasickou koncepcí a důrazem na radost z jízdy.', NULL),
(48, 'Toyota', 'GR86', '2.4 Boxer', 2023, 'Benzín', 172, 'Coupé', 1200000, 5000, '2025-10-22 07:48:37', 'Toyota GR 86 je lehké sportovní kupé, které staví především na řidičském zážitku, vyváženosti a mechanické jednoduchosti. Navazuje na původní GT86 a zůstává věrná klasické koncepci motoru vpředu a pohonu zadních kol. Atmosférický čtyřválcový boxer nabízí lineární nástup výkonu, okamžitou odezvu na plyn a velmi přirozený jízdní projev, díky kterému je GR 86 oblíbená mezi puristy a nadšenci do sportovní jízdy.\n\nZ pohledu automechanika je Toyota GR 86 technicky relativně jednoduchý a poctivý sportovní vůz. Absence turbodmychadla a složité elektroniky znamená nižší riziko drahých poruch a lepší dlouhodobou spolehlivost při správné údržbě. Klíčová je pravidelná výměna oleje, kvalitní mazání a správné zacházení při studeném motoru, zejména kvůli boxerové konstrukci. Podvozek je naladěn tak, aby byl čitelný a zábavný, nikoliv extrémně tvrdý.\n\nMezi hlavní přednosti Toyoty GR 86 patří nízká hmotnost, perfektní vyvážení, pohon zadních kol a čistý řidičský charakter. Nevýhodou je nižší výkon oproti přeplňovaným sportovním vozům, omezená praktičnost a menší komfort na delších trasách. Toyota GR 86 je ideální volbou pro řidiče, kteří chtějí dostupné sportovní auto zaměřené na radost z jízdy, technickou jednoduchost a opravdové zapojení řidiče.', NULL),
(49, 'Subaru', 'BRZ', '2.4 Boxer', 2023, 'Benzín', 172, 'Coupé', 1190000, 4000, '2025-10-22 07:48:37', 'Subaru BRZ je lehké sportovní kupé zaměřené především na čistý řidičský zážitek, vyváženost a přesnou ovladatelnost. Vůz vznikl ve spolupráci s Toyotou a sdílí technický základ s modelem GR 86, přesto si zachovává vlastní charakter typický pro značku Subaru. Díky motoru vpředu, nízkému těžišti a pohonu zadních kol nabízí BRZ velmi čitelné chování v zatáčkách a vysokou míru kontroly nad vozem.\n\nZ pohledu automechanika je Subaru BRZ technicky jednoduchý a poctivý sportovní automobil. Atmosférický čtyřválcový boxer se vyznačuje lineárním nástupem výkonu a dobrým vyvážením, ale vyžaduje pravidelnou údržbu, kvalitní olej a správné zahřívání, zejména kvůli své konstrukci. Absence přeplňování a složité elektroniky znamená nižší riziko drahých poruch a dobrou dlouhodobou spolehlivost při správném zacházení.\n\nMezi hlavní přednosti Subaru BRZ patří nízká hmotnost, nízké těžiště, pohon zadních kol a autentický sportovní charakter. Nevýhodou je nižší výkon ve srovnání s přeplňovanými sportovními vozy, omezená praktičnost a menší komfort na delších trasách. Subaru BRZ je ideální volbou pro řidiče, kteří hledají dostupné sportovní auto zaměřené na techniku, ovladatelnost a radost z jízdy, nikoliv na maximální výkon.', NULL),
(50, 'Mazda', 'MX-5 Miata', '2.0 Skyactiv', 2020, 'Benzín', 135, 'Kabriolet', 890000, 22000, '2025-10-22 07:48:37', 'Mazda MX-5 Miata je ikonický lehký roadster, který dlouhodobě platí za etalon čisté radosti z jízdy. Staví na jednoduché a osvědčené koncepci motoru vpředu a pohonu zadních kol, nízké hmotnosti a otevřené karoserii. Nejde o maximální výkon, ale o vyváženost, přesné řízení a přímé propojení řidiče s vozem, díky čemuž je Miata oblíbená mezi puristy i začátečníky.\n\nZ pohledu automechanika je Mazda MX-5 Miata technicky velmi poctivý a spolehlivý sportovní automobil. Atmosférické motory jsou mechanicky jednoduché, dobře chlazené a při pravidelné údržbě vykazují dlouhou životnost. Podvozek je nenáročný na servis a brzdy i pneumatiky mají díky nízké hmotnosti rozumnou životnost. Mechanismus střechy (plátěné nebo pevné u verzí RF) je konstrukčně jednoduchý, ale vyžaduje občasnou kontrolu a údržbu.\n\nMezi hlavní přednosti Mazdy MX-5 Miata patří nízká hmotnost, výborná ovladatelnost, otevřený jízdní zážitek a vysoká spolehlivost. Nevýhodou je omezený vnitřní prostor, menší praktičnost a nižší výkon oproti silnějším sportovním vozům. Mazda MX-5 Miata je ideální volbou pro řidiče, kteří chtějí dostupný sportovní roadster zaměřený na zábavu, technickou jednoduchost a opravdovou radost z jízdy.', NULL),
(51, 'Mazda', 'RX-8', '1.3 Wankel', 2008, 'Benzín', 170, 'Coupé', 490000, 78000, '2025-10-22 07:48:37', 'Mazda RX-8 je unikátní sportovní vůz, který se výrazně odlišuje od běžné konkurence především použitím rotačního (Wankelova) motoru. Díky kompaktním rozměrům motoru, nízkému těžišti a pohonu zadních kol nabízí RX-8 velmi vyvážené jízdní vlastnosti, přesné řízení a vysokou ochotu k vytáčení do vysokých otáček. Specifickým prvkem jsou také zadní dveře otevírané proti směru jízdy, které zvyšují praktičnost bez narušení sportovního vzhledu.\n\nZ pohledu automechanika je Mazda RX-8 technicky specifický a náročnější vůz na údržbu. Rotační motor vyžaduje pravidelnou kontrolu hladiny oleje, správné zahřívání a častější servis než klasické pístové motory. Při zanedbání údržby může docházet ke snížení komprese a nákladným opravám. Na druhou stranu má motor minimum pohyblivých částí a při správném zacházení dokáže nabídnout velmi hladký chod a dlouhou životnost.\n\nMezi hlavní přednosti Mazdy RX-8 patří jedinečný rotační motor, skvělé vyvážení podvozku, vysoké otáčky a čistý sportovní charakter. Nevýhodou je vyšší spotřeba paliva i oleje, náročnější údržba a menší točivý moment v nízkých otáčkách. Mazda RX-8 je ideální volbou pro nadšence, kteří chtějí technicky výjimečné sportovní auto a jsou ochotni věnovat mu odpovídající péči.', NULL),
(52, 'Chevrolet', 'Corvette C7', '6.2 V8', 2018, 'Benzín', 343, 'Coupé', 1850000, 28000, '2025-10-22 07:48:37', 'Chevrolet Corvette C7 je ikonický americký sportovní vůz, který představuje tradiční pojetí výkonu – velký atmosférický osmiválec, pohon zadních kol a důraz na surový jízdní zážitek. Oproti evropským supersportům nabízí Corvette C7 kombinaci vysokého výkonu, relativně jednoduché techniky a velmi dobrého poměru cena/výkon. Dlouhá kapota, nízký posed za volantem a výrazný zvuk V8 jasně definují charakter tohoto vozu.\n\nZ pohledu automechanika je Corvette C7 mechanicky poctivý a překvapivě robustní sportovní automobil. Atmosférický osmiválcový motor je konstrukčně jednodušší než moderní přeplňované jednotky a při pravidelné údržbě nabízí dobrou spolehlivost. Klíčová je kvalita oleje, správné zahřívání a péče o převodovku a diferenciál, zejména při sportovní jízdě. Podvozek je naladěn sportovně, ale stále zvládnutelně pro běžné silnice.\n\nMezi hlavní přednosti Chevroletu Corvette C7 patří silný atmosférický V8, charismatický zvuk, pohon zadních kol a velmi dobrý výkon za danou cenu. Nevýhodou je horší kvalita interiéru oproti evropské konkurenci, vyšší spotřeba paliva a menší praktičnost v každodenním provozu. Corvette C7 je ideální volbou pro řidiče, kteří chtějí autentický americký sportovní vůz s výrazným charakterem a nechtějí složitou techniku moderních supersportů.', NULL),
(53, 'Chevrolet', 'Camaro SS', '6.2 V8', 2019, 'Benzín', 339, 'Coupé', 1450000, 30000, '2025-10-22 07:48:37', 'Chevrolet Camaro SS je klasický americký muscle car, který staví na jednoduchém receptu – velký atmosférický osmiválec, pohon zadních kol a výrazný sportovní charakter. Verze SS představuje ideální kompromis mezi každodenní použitelností a syrovým výkonem, přičemž nabízí silný zátah, charismatický zvuk V8 a velmi emotivní jízdní projev. Camaro SS není o jemnosti, ale o síle, zvuku a pocitu z jízdy.\n\nZ pohledu automechanika je Camaro SS mechanicky poctivý a relativně jednoduchý sportovní vůz. Atmosférický V8 je robustní jednotka s dlouhou životností, pokud je dodržována pravidelná výměna oleje, správné zahřívání a kvalitní palivo. Absence turbodmychadel a složité hybridní techniky znamená nižší riziko drahých poruch. Na druhou stranu je nutné počítat s vyšším opotřebením pneumatik, brzd a diferenciálu při sportovní jízdě.\n\nMezi hlavní přednosti Chevroletu Camaro SS patří silný atmosférický motor, výrazný zvuk, pohon zadních kol a autentický muscle car charakter. Nevýhodou je vyšší spotřeba paliva, horší výhled z vozu, méně kvalitní interiér oproti evropské konkurenci a omezená praktičnost. Chevrolet Camaro SS je ideální volbou pro řidiče, kteří chtějí čistý americký sportovní zážitek bez zbytečně složité techniky a s maximálním důrazem na emoce.', NULL),
(54, 'Chevrolet', 'Camaro ZL1', '6.2 V8 Supercharged', 2020, 'Benzín', 485, 'Coupé', 1900000, 25000, '2025-10-22 07:48:37', 'Chevrolet Camaro ZL1 je extrémní verze amerického muscle caru, která posouvá koncept Camara na úroveň plnohodnotného supersportu. Oproti verzi SS přináší přeplňovaný osmiválcový motor, výrazně přepracovaný podvozek, masivní brzdy a agresivní aerodynamiku. Camaro ZL1 je navrženo tak, aby zvládalo nejen přímé zrychlení, ale i intenzivní okruhové zatížení, čímž se řadí mezi nejrychlejší muscle cars své generace.\n\nZ pohledu automechanika jde o technicky velmi namáhaný, ale konstrukčně poctivý vůz. Kompresorem přeplňovaný V8 pracuje s vysokým výkonem a teplotami, což klade extrémní nároky na chlazení, mazání a kvalitu provozních kapalin. Podvozek, diferenciál a brzdy jsou dimenzovány na ostrou sportovní jízdu, avšak jejich opotřebení je při agresivním využívání výrazně vyšší. Oproti evropským supersportům zůstává technika relativně přímočará, což zjednodušuje servis, ale rozhodně nesnižuje jeho nákladnost.\n\nMezi hlavní přednosti Chevroletu Camaro ZL1 patří brutální výkon, extrémní akcelerace, surový zvuk V8 a skutečná okruhová schopnost. Nevýhodou je vysoká spotřeba paliva, tvrdší podvozek, horší výhled z vozu a omezená praktičnost. Camaro ZL1 je ideální volbou pro řidiče, kteří chtějí nejostřejší možnou podobu amerického muscle caru a jsou připraveni přijmout jeho náročný charakter i provozní náklady.', NULL),
(55, 'Ford', 'Mustang GT', '5.0 V8', 2020, 'Benzín', 331, 'Coupé', 1390000, 28000, '2025-10-22 07:48:37', 'Ford Mustang GT je ikonický americký muscle car, který staví na tradičních hodnotách – atmosférický osmiválcový motor, pohon zadních kol a výrazný, emotivní projev. Verze GT představuje srdce nabídky Mustangu a nabízí ideální rovnováhu mezi výkonem, použitelností a cenou. Silný V8 poskytuje okamžitý zátah, charismatický zvuk a klasický „old-school“ jízdní zážitek, který je dnes stále vzácnější.\n\nZ pohledu automechanika je Mustang GT mechanicky poctivý a relativně jednoduchý sportovní vůz. Atmosférický osmiválec je robustní jednotka s dobrou životností, pokud je dodržována pravidelná výměna oleje, kvalitní palivo a správné zahřívání motoru. Oproti moderním přeplňovaným motorům je technika méně složitá, což snižuje riziko drahých poruch. Při sportovní jízdě je však nutné počítat s vyšším opotřebením pneumatik, brzd a diferenciálu.\n\nMezi hlavní přednosti Fordu Mustang GT patří silný atmosférický V8, ikonický design, pohon zadních kol a velmi dobrý poměr cena/výkon. Nevýhodou je vyšší spotřeba paliva, horší trakce na mokru oproti čtyřkolkám, tvrdší podvozek a méně kvalitní interiér ve srovnání s evropskou konkurencí. Ford Mustang GT je ideální volbou pro řidiče, kteří chtějí autentický americký muscle car s důrazem na emoce, zvuk a čistou radost z jízdy.', '/assets/model/ford_mustang_gt.glb'),
(56, 'Ford', 'Mustang Mach 1', '5.0 V8', 2022, 'Benzín', 338, 'Coupé', 1790000, 15000, '2025-10-22 07:48:37', 'Ford Mustang Mach 1 je sportovně zaměřená verze legendárního Mustangu, která stojí mezi klasickým GT a extrémním Shelby. Navazuje na slavné označení Mach 1 z historie značky a kombinuje atmosférický osmiválcový motor s výrazně vylepšeným podvozkem, chlazením a aerodynamikou. Oproti Mustang GT je Mach 1 ostřejší, přesnější a lépe připravený na dynamickou jízdu i okruhové využití.\n\nZ pohledu automechanika je Mustang Mach 1 mechanicky velmi poctivý sportovní vůz. Atmosférický V8 je robustní a spolehlivá jednotka, pokud je dodržována pravidelná údržba, kvalitní olej a správné zahřívání. Oproti běžnému GT má Mach 1 zesílené komponenty podvozku, výkonnější brzdy a lepší chlazení motoru i převodovky, což výrazně zvyšuje odolnost při sportovní jízdě. Tyto úpravy však znamenají i vyšší náklady na servis a provozní díly.\n\nMezi hlavní přednosti Fordu Mustang Mach 1 patří silný atmosférický osmiválec, přesnější řízení, sportovní podvozek a výrazný charakter blízký okruhovým verzím. Nevýhodou je vyšší spotřeba paliva, tvrdší podvozek oproti GT a omezená praktičnost. Ford Mustang Mach 1 je ideální volbou pro řidiče, kteří chtějí klasický americký muscle car, ale s důrazem na lepší ovladatelnost, techniku a sportovní využití.', '/assets/model/ford_mustang_gt.glb'),
(57, 'Ford', 'GT', '3.5 V6 EcoBoost', 2019, 'Benzín', 482, 'Coupé', 1500000, 7000, '2025-10-22 07:48:37', 'Ford Mustang EcoBoost je modernější a civilnější pojetí legendárního Mustangu, které kombinuje ikonický design s přeplňovaným čtyřválcovým motorem. Oproti verzím GT a Mach 1 klade větší důraz na každodenní použitelnost, nižší spotřebu a vyváženější jízdní projev, aniž by zcela ztratil sportovní charakter. Díky motoru vpředu a pohonu zadních kol si Mustang EcoBoost zachovává klasickou koncepci a zábavný jízdní styl.\r\n\r\nZ pohledu automechanika je Mustang EcoBoost technicky moderní, ale složitější než atmosférické verze. Přeplňovaný motor pracuje s vyšším tlakem a teplotami, což klade nároky na kvalitní olej, palivo a pravidelný servis. Turbodmychadlo a elektronické řízení motoru zvyšují efektivitu i výkon, ale zároveň znamenají vyšší citlivost na zanedbanou údržbu. Podvozek je oproti GT lehčí a vyváženější, což se pozitivně projevuje v zatáčkách.\r\n\r\nMezi hlavní přednosti Fordu Mustang EcoBoost patří nižší spotřeba, nižší hmotnost na přední nápravě, lepší ovladatelnost a dostupnější provozní náklady. Nevýhodou je méně emotivní zvuk a nižší výkon ve srovnání s osmiválcovými verzemi. Ford Mustang EcoBoost je ideální volbou pro řidiče, kteří chtějí vzhled a charakter Mustangu, ale v modernějším, úspornějším a každodenně použitelném provedení.', '/assets/model/ford_mustang_gt.glb'),
(58, 'Jaguar', 'F-Type R', '5.0 V8', 2021, 'Benzín', 423, 'Coupé', 2950000, 12000, '2025-10-22 07:48:37', 'Jaguar F-Type R je výrazný britský sportovní vůz, který kombinuje elegantní design s brutálním výkonem a emotivním projevem. Verze R stojí na vrcholu nabídky modelu F-Type a je poháněna přeplňovaným osmiválcovým motorem, jenž nabízí mohutný zátah a charakteristický, hlasitý zvuk. Díky pohonu všech kol poskytuje F-Type R velmi dobrou trakci a stabilitu, a to i při vysokém výkonu a dynamické jízdě.\n\nZ pohledu automechanika je Jaguar F-Type R technicky velmi náročný automobil. Přeplňovaný V8 pracuje s vysokým tepelným i mechanickým zatížením, což klade důraz na kvalitní olej, palivo a striktní dodržování servisních intervalů. Pohon AWD, adaptivní podvozek a pokročilá elektronika výrazně zlepšují jízdní vlastnosti, ale zároveň zvyšují složitost a cenu servisu. Při správné údržbě však motor patří mezi spolehlivé a odolné jednotky ve své třídě.\n\nMezi hlavní přednosti Jaguaru F-Type R patří extrémní výkon, charismatický zvuk V8, luxusní interiér a výrazný design. Nevýhodou je vyšší hmotnost, nákladný servis, vyšší spotřeba paliva a menší praktičnost. Jaguar F-Type R je ideální volbou pro řidiče, kteří chtějí sportovní GT s důrazem na emoce, styl a silný motorový projev.', NULL),
(59, 'Jaguar', 'F-Type 400 Sport', '3.0 V6', 2018, 'Benzín', 294, 'Coupé', 1890000, 30000, '2025-10-22 07:48:37', 'Jaguar F-Type 400 Sport je limitovaná sportovní verze modelu F-Type, která stojí mezi základními variantami a vrcholným provedením R. Vyznačuje se výrazným designem, sportovním naladěním a silným přeplňovaným šestiválcovým motorem, jenž nabízí velmi svižnou akceleraci a typický charismatický zvuk. F-Type 400 Sport je koncipován jako sportovní GT vůz, který klade důraz na emoce, styl a dynamickou jízdu, nikoliv pouze na maximální výkon.\n\nZ pohledu automechanika jde o technicky vyspělý, ale rozumně vyvážený sportovní automobil. Přeplňovaný V6 nabízí dobrý poměr mezi výkonem a provozními nároky, přičemž je méně zatížený než osmiválcová verze R. Klíčová je pravidelná údržba, kvalitní olej a kontrola chlazení, zejména při sportovní jízdě. Podvozek a brzdy jsou dimenzovány na dynamický provoz, ale nejsou tak extrémní, což pozitivně ovlivňuje dlouhodobou použitelnost i servisní náklady.\n\nMezi hlavní přednosti Jaguaru F-Type 400 Sport patří atraktivní design, silný a kultivovaný motor, sportovní charakter a exkluzivita limitované edice. Nevýhodou je vyšší pořizovací cena, omezená praktičnost a nákladnější servis oproti běžným sportovním vozům. Jaguar F-Type 400 Sport je ideální volbou pro řidiče, kteří chtějí výrazné sportovní GT s emotivním projevem, ale bez extrémů nejvýkonnějších verzí.', NULL),
(60, 'Jaguar', 'XKR', '5.0 V8', 2015, 'Benzín', 375, 'Coupé', 1650000, 35000, '2025-10-22 07:48:37', 'Jaguar XKR je luxusní sportovní vůz typu grand tourer, který kombinuje elegantní britský design s výrazným výkonem osmiválcového motoru. Oproti modernějším a ostřeji laděným modelům F-Type působí XKR klidněji a dospěleji, přičemž klade důraz na komfort, plynulost jízdy a dlouhé cestování ve vysokém tempu. Kompresorem přeplňovaný V8 nabízí silný, lineární zátah a typicky kultivovaný, ale zároveň charismatický zvuk.\n\nZ pohledu automechanika je Jaguar XKR technicky robustní, ale náročný na údržbu. Přeplňovaný osmiválec pracuje s vysokým tepelným zatížením, což klade důraz na kvalitní olej, správné chlazení a pravidelné servisní intervaly. Podvozek je naladěn komfortněji než u čistě sportovních modelů, což snižuje opotřebení při běžném provozu, avšak hmotnost vozu a výkon motoru se při dynamické jízdě projeví vyšší zátěží na brzdy a pneumatiky.\n\nMezi hlavní přednosti Jaguaru XKR patří silný osmiválcový motor, elegantní design, vysoký komfort a velmi dobré cestovní schopnosti. Nevýhodou je vyšší hmotnost, nákladný servis, vyšší spotřeba paliva a méně sportovní projev oproti moderním supersportům. Jaguar XKR je ideální volbou pro řidiče, kteří chtějí luxusní GT s výkonem V8, důrazem na styl, komfort a charismatický projev.', NULL),
(61, 'Lotus', 'Emira', '3.5 V6', 2023, 'Benzín', 298, 'Coupé', 2800000, 3000, '2025-10-22 07:48:37', 'Lotus Emira je moderní sportovní vůz, který představuje poslední čistě spalovací model značky Lotus a zároveň vyvrcholení její dlouholeté filozofie zaměřené na nízkou hmotnost a maximální řidičský zážitek. Díky motoru uloženému uprostřed a pohonu zadních kol nabízí Emira výjimečně vyvážené jízdní vlastnosti, přesné řízení a velmi přímou odezvu na chování vozu. Oproti starším modelům Lotus působí Emira dospěleji a komfortněji, aniž by ztratila svůj sportovní charakter.\n\nZ pohledu automechanika je Lotus Emira technicky poctivý, ale stále ryze sportovní automobil. Konstrukce klade důraz na nízkou hmotnost, jednoduchost a mechanickou čistotu. Motor uložený uprostřed vyžaduje důsledné dodržování servisních intervalů a kvalitní provozní kapaliny, zejména při sportovní jízdě. Podvozek je naladěn velmi precizně, což znamená vysokou stabilitu a kontrolu, ale také vyšší citlivost na stav pneumatik a geometrie náprav.\n\nMezi hlavní přednosti Lotusu Emira patří výjimečná ovladatelnost, nízká hmotnost, pohon zadních kol a autentický řidičský zážitek. Nevýhodou je omezená praktičnost, menší zavazadlový prostor, vyšší nároky na řidiče a užší zaměření na sportovní jízdu. Lotus Emira je ideální volbou pro nadšence, kteří hledají moderní sportovní auto s tradiční filozofií Lotusu a chtějí si jízdu skutečně „odřídit“.', NULL),
(62, 'Lotus', 'Evora 400', '3.5 V6', 2020, 'Benzín', 298, 'Coupé', 2400000, 9000, '2025-10-22 07:48:37', 'Lotus Evora 400 je sportovní vůz s motorem uloženým uprostřed, který kombinuje tradiční filozofii značky Lotus – nízkou hmotnost a precizní ovladatelnost – s výrazně vyšším výkonem a dospělejším pojetím. Oproti starším modelům Lotusu nabízí Evora 400 lepší použitelnost, komfortnější interiér a zároveň velmi ostrý sportovní charakter. Díky pohonu zadních kol a přesně naladěnému podvozku patří mezi auta, která kladou důraz především na řidiče.\n\nZ pohledu automechanika je Lotus Evora 400 technicky poctivý, ale sportovně náročný automobil. Přeplňovaný šestiválcový motor poskytuje silný a plynulý zátah, přičemž klíčová je pravidelná údržba, kvalitní olej a důsledné zahřívání motoru. Podvozek je velmi citlivý na správné nastavení geometrie a stav pneumatik, což má zásadní vliv na jízdní vlastnosti. Mechanika je relativně jednoduchá, ale servisní přístupnost je kvůli středovému uložení motoru omezenější.\n\nMezi hlavní přednosti Lotusu Evora 400 patří výjimečná ovladatelnost, nízká hmotnost, silný motor a autentický sportovní projev. Nevýhodou je omezená praktičnost, menší komfort oproti prémiovým sportovním vozům a vyšší nároky na řidiče i údržbu. Lotus Evora 400 je ideální volbou pro nadšence, kteří hledají skutečný řidičský vůz a chtějí sportovní auto bez zbytečných kompromisů a elektronických berliček.', NULL),
(63, 'Alfa Romeo', '4C', '1.75 Turbo', 2018, 'Benzín', 177, 'Coupé', 1450000, 18000, '2025-10-22 07:48:37', 'Alfa Romeo 4C je extrémně lehký sportovní vůz, který staví na čisté mechanice, nízké hmotnosti a maximálním řidičském zážitku. Díky karbonovému monokoku, motoru uloženému uprostřed a pohonu zadních kol nabízí 4C velmi ostrý, bezprostřední jízdní projev. Nejde o komfort ani každodenní použitelnost, ale o emoce, zvuk a přímé propojení řidiče s vozem – přesně v duchu tradičních sportovních Alf.\n\nZ pohledu automechanika je Alfa Romeo 4C technicky specifický a náročnější automobil. Karbonová vana zajišťuje vysokou tuhost a nízkou hmotnost, ale výrazně zvyšuje náklady na případné opravy. Přeplňovaný čtyřválcový motor poskytuje velmi dobrý výkon vzhledem k hmotnosti vozu, avšak vyžaduje kvalitní olej, správné zahřívání a pečlivou údržbu. Podvozek je tvrdý a velmi citlivý na stav pneumatik i geometrii, což má zásadní vliv na jízdní vlastnosti.\n\nMezi hlavní přednosti Alfy Romeo 4C patří extrémně nízká hmotnost, karbonová konstrukce, výjimečná ovladatelnost a silný emotivní charakter. Nevýhodou je minimální komfort, horší každodenní použitelnost, omezená praktičnost a nákladný servis při poškození. Alfa Romeo 4C je ideální volbou pro nadšence, kteří chtějí ryzí sportovní auto bez kompromisů a jsou ochotni obětovat pohodlí ve prospěch čistého řidičského zážitku.', NULL),
(64, 'Alfa Romeo', 'Giulia Quadrifoglio', '2.9 V6', 2020, 'Benzín', 375, 'Sedan', 2300000, 22000, '2025-10-22 07:48:37', 'Alfa Romeo Giulia Quadrifoglio je vysoce výkonný sportovní sedan, který spojuje italské emoce s technikou zaměřenou na maximální jízdní zážitek. Verze Quadrifoglio představuje vrchol modelové řady Giulia a je poháněna přeplňovaným šestiválcovým motorem, který nabízí explozivní zrychlení, výrazný zvuk a velmi lehký předek vozu. Díky pohonu zadních kol a nízké hmotnosti působí Giulia mimořádně agilně a řidičsky zaměřeně.\n\nZ pohledu automechanika je Giulia Quadrifoglio technicky velmi ambiciózní automobil. Výkonný V6 pracuje s vysokým plnicím tlakem a teplotami, což klade důraz na kvalitní olej, palivo a striktní dodržování servisních intervalů. Podvozek je naladěn extrémně sportovně a je citlivý na stav pneumatik, brzd a správné nastavení geometrie. Pokročilá elektronika a aktivní aerodynamika zvyšují jízdní schopnosti, ale zároveň znamenají vyšší náročnost servisu.\n\nMezi hlavní přednosti Alfy Romeo Giulia Quadrifoglio patří výjimečná ovladatelnost, nízká hmotnost, charismatický motor a silný emotivní projev. Nevýhodou je nákladnější servis, vyšší citlivost na údržbu a menší důraz na komfort oproti německé konkurenci. Alfa Romeo Giulia Quadrifoglio je ideální volbou pro řidiče, kteří chtějí sportovní sedan s výrazným charakterem, emocemi a skutečnou radostí z jízdy.', NULL),
(65, 'Renault', 'Mégane RS Trophy', '1.8 Turbo', 2021, 'Benzín', 221, 'Hatchback', 1150000, 25000, '2025-10-22 07:48:37', 'Renault Mégane RS Trophy je extrémně sportovní hot-hatch, který byl vyvinut s jasným cílem – maximální výkon a efektivita na závodním okruhu. Oproti standardnímu Mégane RS nabízí ještě ostřejší naladění motoru, podvozku a brzd, díky čemuž patří mezi nejrychlejší předokolky své třídy. Vůz je zaměřen především na přesnost, stabilitu a rychlost v zatáčkách, nikoliv na komfort.\n\nZ pohledu automechanika je Mégane RS Trophy technicky velmi zajímavý, ale náročný automobil. Přeplňovaný čtyřválcový motor pracuje s vysokým výkonem a tepelným zatížením, což klade důraz na kvalitní olej, častější servis a správné zahřívání. Klíčovým prvkem je samosvorný diferenciál, který výrazně zlepšuje trakci přední nápravy, ale zároveň zvyšuje zatížení pneumatik a podvozkových komponent. Tuhý podvozek a výkonné brzdy jsou ideální na okruh, ale méně tolerantní k nekvalitním silnicím.\n\nMezi hlavní přednosti Renaultu Mégane RS Trophy patří extrémně přesné řízení, vynikající chování v zatáčkách, silný motor a skutečný okruhový charakter. Nevýhodou je tvrdý podvozek, nižší komfort, vyšší opotřebení provozních dílů a menší vhodnost pro každodenní jízdu. Renault Mégane RS Trophy je ideální volbou pro řidiče, kteří chtějí jeden z nejostřejších hot-hatchů na trhu a plánují časté sportovní nebo okruhové využití.', NULL),
(66, 'Renault', 'Alpine A110', '1.8 Turbo', 2022, 'Benzín', 215, 'Coupé', 1800000, 8000, '2025-10-22 07:48:37', 'Alpine A110 je moderní sportovní vůz, který navazuje na slavnou historii značky Alpine a staví na jednoduché, ale velmi účinné filozofii – nízká hmotnost, motor uložený uprostřed a maximální radost z jízdy. Nehoní se za extrémním výkonem, ale za dokonalým vyvážením, agilitou a čistým řidičským zážitkem. Díky kompaktním rozměrům a lehké konstrukci působí A110 mimořádně hravě a přesně v zatáčkách.\n\nZ pohledu automechanika je Alpine A110 technicky chytrý a relativně jednoduchý sportovní automobil. Nízká hmotnost výrazně snižuje zatížení brzd, pneumatik i podvozkových komponent. Přeplňovaný čtyřválcový motor poskytuje dostatek výkonu, aniž by byl extrémně namáhán, což má pozitivní vliv na dlouhodobou spolehlivost. Klíčová je pravidelná údržba, kvalitní olej a správné zahřívání, zejména při sportovní jízdě.\n\nMezi hlavní přednosti Alpine A110 patří nízká hmotnost, výjimečná ovladatelnost, skvělé vyvážení a čistý sportovní charakter. Nevýhodou je omezená praktičnost, menší vnitřní prostor a menší důraz na luxusní výbavu. Alpine A110 je ideální volbou pro řidiče, kteří hledají moderní sportovní auto zaměřené na techniku, lehkost a opravdovou radost z jízdy.', NULL),
(67, 'Peugeot', 'RCZ R', '1.6 THP', 2015, 'Benzín', 199, 'Coupé', 790000, 42000, '2025-10-22 07:48:37', 'Peugeot RCZ R je sportovní kupé, které představuje nejostřejší a nejvýkonnější verzi modelu RCZ. Oproti běžným variantám nabízí výrazně vyšší výkon, sportovnější naladění a techniku zaměřenou na dynamickou jízdu. Díky přeplňovanému čtyřválcovému motoru a pohonu předních kol dokáže RCZ R nabídnout velmi rychlou akceleraci a překvapivě schopné chování v zatáčkách, čímž se řadí mezi nejzajímavější předokolky své doby.\n\nZ pohledu automechanika je Peugeot RCZ R technicky zajímavý, ale náročnější automobil. Výkonný přeplňovaný motor pracuje s vysokým plnicím tlakem, což klade důraz na kvalitní olej, pravidelný servis a správné zahřívání. Klíčovým prvkem je mechanický samosvorný diferenciál Torsen, který výrazně zlepšuje trakci a ovladatelnost přední nápravy, ale zároveň zvyšuje zatížení pneumatik a podvozkových komponent. Podvozek je naladěn sportovně, což se pozitivně projevuje v zatáčkách, ale snižuje komfort na horších silnicích.\n\nMezi hlavní přednosti Peugeotu RCZ R patří silný motor, velmi dobrá trakce předních kol, výrazný design a sportovní charakter. Nevýhodou je tvrdší podvozek, vyšší nároky na údržbu, omezená praktičnost a menší využitelnost zadních sedadel. Peugeot RCZ R je ideální volbou pro řidiče, kteří chtějí netradiční sportovní kupé s předním pohonem a výrazným charakterem, odlišné od běžné konkurence.', '/assets/model/peugeot_rcz.glb'),
(68, 'Volkswagen', 'Golf R', '2.0 TSI', 2021, 'Benzín', 235, 'Hatchback', 1550000, 22000, '2025-10-22 07:48:37', 'Volkswagen Golf R (2021) představuje vrchol sportovní nabídky modelové řady Golf a kombinuje vysoký výkon s každodenní použitelností. Oproti verzím GTI nabízí pohon všech kol 4Motion, vyšší výkon a výrazně jistější chování při dynamické jízdě. Golf R je koncipován jako rychlý, univerzální hot-hatch, který zvládá jak svižnou jízdu po okreskách, tak běžné každodenní fungování bez kompromisů.\n\nZ pohledu automechanika je Golf R technicky vyspělý, ale poměrně robustní automobil. Přeplňovaný dvoulitrový čtyřválec je osvědčená jednotka koncernu VW, která při pravidelné údržbě nabízí dobrou spolehlivost. Pohon všech kol 4Motion výrazně zlepšuje trakci, ale zároveň zvyšuje složitost servisních zásahů a nároky na údržbu spojky, převodovky a diferenciálů. Sportovní podvozek a výkonné brzdy jsou dimenzovány na vyšší zatížení, což se při dynamické jízdě může projevit rychlejším opotřebením provozních dílů.\n\nMezi hlavní přednosti Volkswagenu Golf R (2021) patří vysoký výkon, vynikající trakce, univerzálnost a kvalitní zpracování interiéru. Nevýhodou je vyšší hmotnost, nákladnější servis oproti předokolkám a menší „syrovost“ ve srovnání s ryze okruhově laděnými hot-hatchi. Golf R je ideální volbou pro řidiče, kteří chtějí velmi rychlé, ale zároveň komfortní a celoročně použitelné sportovní auto.', '/assets/model/2025_volkswagen_golf_r.glb'),
(69, 'Volkswagen', 'Scirocco R', '2.0 TSI', 2017, 'Benzín', 206, 'Coupé', 980000, 50000, '2025-10-22 07:48:37', 'Volkswagen Scirocco R je sportovní kupé, které představuje nejostřejší variantu modelové řady Scirocco. Oproti klasickému Golfu GTI působí výrazně sportovnějším a emotivnějším dojmem, přičemž klade důraz na design, dynamiku a řidičský zážitek. Přeplňovaný dvoulitrový motor nabízí silný zátah a velmi svižnou akceleraci, díky čemuž se Scirocco R řadí mezi nejrychlejší předokolky své doby.\n\nZ pohledu automechanika je Scirocco R technicky osvědčený, ale sportovně namáhaný vůz. Přeplňovaný motor patří mezi prověřené jednotky koncernu VW, avšak pracuje s vyšším výkonem, což klade nároky na kvalitní olej, pravidelný servis a správné zahřívání. Pohon předních kol bez samosvorného diferenciálu vyžaduje kvalitní pneumatiky a dobrý cit řidiče, zejména při agresivní jízdě. Podvozek je naladěn sportovně, což zlepšuje chování v zatáčkách, ale snižuje komfort na horších silnicích.\n\nMezi hlavní přednosti Volkswagenu Scirocco R patří atraktivní sportovní design, silný motor, nízký posed za volantem a velmi dobré jízdní vlastnosti. Nevýhodou je omezená praktičnost, menší vnitřní prostor, tvrdší podvozek a horší trakce oproti verzím s pohonem všech kol. Volkswagen Scirocco R je ideální volbou pro řidiče, kteří chtějí sportovní kupé s výrazným vzhledem a výkonem, ale nevyžadují maximální praktičnost.', '/assets/model/2015_volkswagen_scirocco_r.glb'),
(70, 'Seat', 'Leon Cupra', '2.0 TSI', 2020, 'Benzín', 228, 'Hatchback', 920000, 30000, '2025-10-22 07:48:37', 'SEAT Leon Cupra 2.0 TSI je vysoce výkonný sportovní hatchback, který dlouhodobě patří mezi nejrychlejší vozy ve své třídě. Oproti běžným verzím Leona nabízí výrazně vyšší výkon, sportovní podvozek a agresivnější charakter. V závislosti na generaci je k dispozici s pohonem předních kol nebo všech kol, což dává Cuprě velmi dobré jízdní vlastnosti jak na suchu, tak v horších podmínkách. Cupra je zaměřená na rychlost, přesnost a maximální využití výkonu.\n\nZ pohledu automechanika je Leon Cupra technicky vyspělý, ale sportovně namáhaný automobil. Přeplňovaný dvoulitrový motor TSI je osvědčená koncernová jednotka, která při pravidelné údržbě nabízí dobrou spolehlivost, avšak pracuje s vysokým výkonem a teplotami. Klíčovou roli hraje samosvorný diferenciál (u předokolek), který výrazně zlepšuje trakci, ale zvyšuje zatížení pneumatik a přední nápravy. Sportovní podvozek a výkonné brzdy vyžadují častější servis při dynamické jízdě.\n\nMezi hlavní přednosti SEAT Leon Cupra 2.0 TSI patří vysoký výkon, výborné jízdní vlastnosti, velmi dobrý poměr cena/výkon a relativně dobrá každodenní použitelnost. Nevýhodou je tvrdší podvozek, vyšší opotřebení provozních dílů při sportovní jízdě a méně prémiový interiér oproti Audi či BMW. SEAT Leon Cupra je ideální volbou pro řidiče, kteří chtějí extrémně rychlý hot-hatch s ostrým charakterem a bez zbytečných kompromisů.', '/assets/model/2021_cupra_leon_5door.glb');
INSERT INTO `cars` (`id`, `brand`, `model`, `variant`, `year`, `fuel`, `power_kw`, `body`, `price`, `mileage`, `created_at`, `description`, `model_3d`) VALUES
(71, 'Cupra', 'Formentor VZ', '2.0 TSI', 2021, 'Benzín', 228, 'SUV', 1190000, 18000, '2025-10-22 07:48:37', 'CUPRA Formentor VZ je sportovně laděný crossover, který kombinuje praktičnost moderního SUV s výkonem a charakterem vozů CUPRA. Oproti běžným verzím Formentoru nabízí varianta VZ výrazně vyšší výkon, sportovní podvozek a agresivnější design. Díky silnému přeplňovanému motoru a pohonu všech kol (u vybraných verzí) poskytuje Formentor VZ velmi rychlou akceleraci, vysokou stabilitu a jistotu i při dynamické jízdě.\n\nZ pohledu automechanika je CUPRA Formentor VZ technicky vyspělý, ale sportovně namáhaný automobil. Přeplňovaný motor pracuje s vysokým výkonem a teplotami, což klade důraz na kvalitní olej, palivo a pravidelné servisní intervaly. Pohon všech kol a moderní elektronické systémy zlepšují trakci a ovladatelnost, ale zároveň zvyšují složitost a náklady na servis. Sportovní podvozek a brzdy jsou dimenzovány na vyšší zatížení, což se při svižné jízdě projeví rychlejším opotřebením provozních dílů.\n\nMezi hlavní přednosti CUPRA Formentor VZ patří kombinace vysokého výkonu, atraktivního designu, praktičnosti a každodenní použitelnosti. Nevýhodou je vyšší hmotnost oproti klasickým hot-hatchům, nákladnější servis a vyšší spotřeba při dynamické jízdě. CUPRA Formentor VZ je ideální volbou pro řidiče, kteří chtějí sportovní charakter a výkon, ale zároveň potřebují prostor a univerzálnost moderního crossoveru.', '/assets/model/cupra_formentor_2021.glb'),
(72, 'Cupra', 'Born', 'Elektro 170 kW', 2023, 'Elektro', 170, 'Hatchback', 950000, 8000, '2025-10-22 07:48:37', 'CUPRA Born je plně elektrický sportovní hatchback, který přenáší charakter značky CUPRA do světa elektromobility. Oproti běžným elektromobilům klade důraz na dynamiku, design a řidičský zážitek, nikoliv pouze na úspornost. Díky okamžitému nástupu výkonu elektromotoru nabízí Born velmi svižnou akceleraci, tichý chod a plynulý jízdní projev, který je ideální jak do města, tak na svižnou jízdu mimo něj.\n\nZ pohledu automechanika je CUPRA Born technicky zcela odlišný vůz oproti spalovacím modelům. Absence klasického motoru, převodovky a výfukového systému výrazně snižuje mechanické opotřebení a nároky na běžný servis. Klíčovými komponenty jsou vysokonapěťová baterie, elektromotor a chladicí systémy, jejichž správná funkce závisí hlavně na softwaru a elektronice. Servis se tak více zaměřuje na diagnostiku, aktualizace systému a kontrolu elektrických částí.\n\nMezi hlavní přednosti CUPRA Born patří okamžitá akcelerace, tichý chod, moderní technologie a nízké provozní náklady. Nevýhodou je vyšší hmotnost baterie, omezený dojezd při dynamické jízdě a závislost na nabíjecí infrastruktuře. CUPRA Born je ideální volbou pro řidiče, kteří chtějí sportovně laděný elektromobil s výrazným designem a moderním charakterem, ale zároveň očekávají každodenní použitelnost.', '/assets/model/2022-2024_cupra_born.glb'),
(73, 'Hyundai', 'i30 N Performance', '2.0 T-GDI', 2021, 'Benzín', 206, 'Hatchback', 890000, 24000, '2025-10-22 07:48:37', 'Hyundai i30 N Performance je ostrý sportovní hatchback, který vznikl s jasným cílem – nabídnout maximální zábavu za volantem a skutečný řidičský charakter. Oproti běžným verzím i30 přináší výrazně silnější motor, tužší podvozek, výkonné brzdy a sportovní prvky inspirované okruhovým využitím. i30 N Performance je zaměřena na emoce, zvuk a aktivní zapojení řidiče, nikoliv pouze na komfort.\n\nZ pohledu automechanika je Hyundai i30 N Performance technicky poctivý a relativně robustní sportovní vůz. Přeplňovaný čtyřválcový motor nabízí silný zátah a dobrý výkon, přičemž při pravidelné údržbě a kvalitním oleji vykazuje solidní spolehlivost. Klíčovým prvkem je elektronicky řízený samosvorný diferenciál, který výrazně zlepšuje trakci přední nápravy, ale zároveň zvyšuje zatížení pneumatik a podvozkových komponent. Podvozek je naladěn velmi tuze, což prospívá jízdě na okreskách i okruhu, ale snižuje komfort na rozbitých silnicích.\n\nMezi hlavní přednosti Hyundai i30 N Performance patří skvělý zvuk, přesné řízení, velmi dobré chování v zatáčkách a výborný poměr cena/výkon. Nevýhodou je tvrdší podvozek, vyšší spotřeba při sportovní jízdě a menší komfort oproti civilnějším hot-hatchům. Hyundai i30 N Performance je ideální volbou pro řidiče, kteří chtějí autentický sportovní hatchback zaměřený na radost z jízdy a nevadí jim obětovat část pohodlí ve prospěch zážitku.', '/assets/model/2018_hyundai_i30_n.glb'),
(74, 'Kia', 'Stinger GT', '3.3 V6 Turbo', 2019, 'Benzín', 272, 'Liftback', 1100000, 40000, '2025-10-22 07:48:37', 'Kia Stinger GT je sportovně laděný fastback, který výrazně změnil vnímání značky Kia v segmentu výkonných vozů. Nabízí elegantní design, silný motor a koncepci s motorem vpředu a pohonem zadních kol (případně AWD), což z něj dělá plnohodnotný sportovní sedan s důrazem na stabilitu a komfort při vysokých rychlostech. Stinger GT je koncipován jako rychlé gran turismo, vhodné jak na dynamickou jízdu, tak na dlouhé dálniční přesuny.\n\nZ pohledu automechanika je Kia Stinger GT technicky velmi zajímavý a relativně robustní automobil. Výkonný přeplňovaný motor nabízí silný a plynulý zátah, přičemž při pravidelné údržbě a kvalitním oleji vykazuje dobrou spolehlivost. Podvozek je naladěn spíše komfortně-sportovně, což snižuje opotřebení komponent při běžném provozu. Pohon zadních kol přináší zábavný jízdní projev, ale zároveň klade vyšší nároky na pneumatiky při sportovní jízdě.\n\nMezi hlavní přednosti Kia Stinger GT patří silný motor, stabilní jízdní vlastnosti, vysoký komfort, atraktivní design a velmi dobrý poměr cena/výkon. Nevýhodou je vyšší hmotnost, méně prémiový image oproti zavedeným německým značkám a vyšší spotřeba při dynamické jízdě. Kia Stinger GT je ideální volbou pro řidiče, kteří chtějí výkonný sportovní sedan s charakterem GT, ale zároveň očekávají komfort, prostor a každodenní použitelnost.', '/assets/model/kia_stinger.glb'),
(75, 'Tesla', 'Model S Plaid', 'Elektro', 2022, 'Elektro', 750, 'Sedan', 2500000, 20000, '2025-10-22 07:48:37', 'Tesla Model S Plaid je jeden z nejrychlejších sériově vyráběných automobilů na světě a jasně ukazuje, kam se elektromobilita posunula. Díky trojici elektromotorů a pohonu všech kol nabízí extrémní akceleraci, okamžitou odezvu a výkon, který překonává většinu spalovacích supersportů. Model S Plaid je koncipován jako technologická vlajková loď Tesly, která kombinuje brutální výkon s relativně nenápadným vzhledem a praktickou karoserií sedanu.\n\nZ pohledu automechanika je Tesla Model S Plaid technicky zcela odlišný vůz oproti klasickým sportovním autům. Absence spalovacího motoru, převodovky a výfukového systému výrazně snižuje počet mechanicky namáhaných dílů a běžné servisní úkony. Klíčovou roli hrají elektromotory, vysokonapěťová baterie, chlazení a software, který řídí výkon i stabilitu vozu. Servis se tak soustředí hlavně na diagnostiku, aktualizace softwaru a kontrolu elektrických a chladicích systémů, zatímco brzdy a pneumatiky trpí vysokým výkonem a hmotností.\n\nMezi hlavní přednosti Tesly Model S Plaid patří extrémní akcelerace, tichý a plynulý chod, moderní technologie a vysoká praktičnost. Nevýhodou je vysoká hmotnost, menší emoční projev oproti spalovacím vozům, náročné chlazení při opakované zátěži a závislost na nabíjecí infrastruktuře. Tesla Model S Plaid je ideální volbou pro řidiče, kteří chtějí absolutní výkon a nejmodernější technologie v elektrickém balení bez kompromisů v praktičnosti.', '/assets/model/3d_model_tesla_s.glb'),
(76, 'Tesla', 'Roadster', 'Elektro', 2023, 'Elektro', 1000, 'Coupé', 5500000, 2000, '2025-10-22 07:48:37', 'Tesla Roadster (2023) je elektrický supersport, který si klade za cíl redefinovat samotné hranice výkonu a rychlosti sériových automobilů. Jde o otevřený roadster s futurickým designem, zaměřený na extrémní akceleraci, vysokou maximální rychlost a technologickou dominanci. Roadster má ambici překonat tradiční spalovací hypersporty nejen v přímce, ale i v celkovém pojetí moderního sportovního vozu.\r\n\r\nZ pohledu automechanika je Tesla Roadster technicky zcela odlišný od klasických supersportů. Elektrický pohon eliminuje složité mechanické systémy, jako jsou převodovky, spojky či výfukové soustavy, čímž výrazně snižuje mechanické opotřebení. Naopak klíčovou roli hrají elektromotory, vysokokapacitní baterie, sofistikované chlazení a pokročilý software řídící výkon i stabilitu. Servis se proto zaměřuje především na diagnostiku, elektroniku a teplotní management, zatímco brzdy a pneumatiky jsou extrémně zatěžovány kvůli vysokému výkonu.\r\n\r\nMezi hlavní přednosti Tesly Roadster (2023) patří extrémní akcelerace, futurická technologie, tichý chod a nulové lokální emise. Nevýhodou je velmi vysoká pořizovací cena, vysoká hmotnost baterií, závislost na nabíjecí infrastruktuře a menší emoční projev oproti spalovacím hypersportům. Tesla Roadster je ideální volbou pro řidiče, kteří chtějí absolutní výkon a technologickou špičku bez kompromisů a zároveň chtějí být součástí nové éry supersportů.', '/assets/model/tesla_roadster_2020.glb');

